  &lt;script src=&quot;https://d3js.org/d3.v7.min.js&quot;&gt;&lt;/script&gt;
  &lt;script src=&quot;https://cdnjs.cloudflare.com/ajax/libs/animejs/3.2.1/anime.min.js&quot;&gt;&lt;/script&gt;
  &lt;script src=&quot;https://cdn.jsdelivr.net/npm/sortablejs@latest/Sortable.min.js&quot;&gt;&lt;/script&gt;
  &lt;style&gt;
    /* small helpful utility to keep HTML compact */
    .icon-btn{display:flex;flex-direction:column;align-items:center}
  &lt;/style&gt;
&lt;/head&gt;
&lt;body class=&quot;min-h-screen bg-gray-900 text-white font-sans&quot;&gt;
  &lt;div id=&quot;root&quot;&gt;&lt;/div&gt;
  &lt;script crossorigin src=&quot;https://unpkg.com/react@18/umd/react.development.js&quot;&gt;&lt;/script&gt;
  &lt;script crossorigin src=&quot;https://unpkg.com/react-dom@18/umd/react-dom.development.js&quot;&gt;&lt;/script&gt;
  &lt;script src=&quot;https://unpkg.com/@babel/standalone/babel.min.js&quot;&gt;&lt;/script&gt;
  &lt;!-- load app.js (JSX) via Babel standalone so its components/providers are available to the inline mount below --&gt;
  &lt;script type=&quot;text/babel&quot; src=&quot;app.js&quot;&gt;&lt;/script&gt;
  &lt;!-- main compact React UI that renders dynamic sections by mapping data arrays --&gt;
  &lt;script type=&quot;text/babel&quot;&gt;
    const { useEffect } = React;
    const sidebarItems = [
      {icon: &apos;fa-bars&apos;, action: null, compact: false},
      {icon: &apos;fa-plus&apos;, label: &apos;Create&apos;, badgeBg:&apos;bg-purple-500&apos;},
      {icon: &apos;fa-home&apos;, label: &apos;Home&apos;},
      {icon: &apos;fa-folder&apos;, label: &apos;Projects&apos;},
      {icon: &apos;fa-th&apos;, label: &apos;Templates&apos;, action: &apos;toggleTemplates&apos;},
      {icon: &apos;fa-crown&apos;, label: &apos;Brand&apos;, badgeBg:&apos;bg-yellow-500&apos;},
      // {icon: &apos;fa-magic&apos;, label: &apos;Canva AI&apos;},
      // {icon: &apos;fa-app-store&apos;, label: &apos;Apps&apos;},   
      {icon: &apos;fa-bell&apos;, label: &apos;Notifications&apos;, action:&apos;toggleNotifications&apos;},
    ];
    const modules = [
      [&apos;storywriter&apos;,&apos;feather-alt&apos;,&apos;Storywriter&apos;,&apos;bg-blue-500&apos;],
      [&apos;scriptwriter&apos;,&apos;file-alt&apos;,&apos;Scriptwriter&apos;,&apos;bg-teal-500&apos;],
      [&apos;showrunner&apos;,&apos;tv&apos;,&apos;Showrunner&apos;,&apos;bg-green-500&apos;],
      [&apos;director&apos;,&apos;video&apos;,&apos;Director&apos;,&apos;bg-orange-500&apos;],
      [&apos;dop&apos;,&apos;camera&apos;,&apos;DoP Module&apos;,&apos;bg-red-500&apos;],
      [&apos;ad&apos;,&apos;clipboard-list&apos;,&apos;AD Module&apos;,&apos;bg-pink-500&apos;],
      [&apos;production-design&apos;,&apos;hammer&apos;,&apos;Production Design&apos;,&apos;bg-purple-500&apos;],
      [&apos;costume&apos;,&apos;tshirt&apos;,&apos;Costume&apos;,&apos;bg-indigo-500&apos;],
      [&apos;vfx&apos;,&apos;magic&apos;,&apos;VFX Module&apos;,&apos;bg-yellow-500&apos;],
      [&apos;composer&apos;,&apos;music&apos;,&apos;Composer&apos;,&apos;bg-cyan-500&apos;],
      [&apos;editor&apos;,&apos;cut&apos;,&apos;Editor&apos;,&apos;bg-emerald-500&apos;],
      [&apos;colorist&apos;,&apos;palette&apos;,&apos;Colorist&apos;,&apos;bg-rose-500&apos;]
    ];
    const releases = [
      {title:&apos;Echoes of Tomorrow - Full Feature&apos;, img:&apos;https://via.placeholder.com/300x150/2563EB/FFFFFF?text=Sci-Fi+Feature&apos;,meta:&apos;Created with NarratingOS • Director: Maya Chen&apos;},
      {title:&apos;Midnight Café - Short Film Series&apos;, img:&apos;https://via.placeholder.com/300x150/7C3AED/FFFFFF?text=Drama+Series&apos;,meta:&apos;Created with NarratingOS • Director: Alex Rivera&apos;},
      {title:&apos;Urban Pulse - Documentary&apos;, img:&apos;https://via.placeholder.com/300x150/0EA5E9/FFFFFF?text=Documentary&apos;,meta:&apos;Created with NarratingOS • Director: Sam Johnson&apos;}
    ];
    function Sidebar(){
      return (
        &lt;aside className=&quot;fixed left-0 top-0 h-full w-20 bg-gradient-to-b from-indigo-900 to-blue-900 z-50 flex flex-col items-center py-4&quot;&gt;
          {sidebarItems.map((it,i)=&gt;(
            &lt;button
              key={i}
              className=&quot;text-white mb-4 p-2 rounded-full hover:bg-indigo-700 transition-colors duration-200&quot;
              data-action={it.action || undefined}
              onClick={it.icon === &apos;fa-home&apos; ? (e=&gt;{ e.preventDefault(); window.location.href = &apos;index.html&apos;; }) : undefined}
            &gt;
              &lt;div className={it.badgeBg ? `w-10 h-10 ${it.badgeBg} rounded-full flex items-center justify-center mb-1` : &apos;&apos;}&gt;
                &lt;i className={`fas ${it.icon} ${it.badgeBg ? &apos;text-white&apos; : &apos;text-white&apos;}`}&gt;&lt;/i&gt;
              &lt;/div&gt;
              {it.label &amp;&amp; &lt;span className=&quot;text-xs&quot;&gt;{it.label}&lt;/span&gt;}
            &lt;/button&gt;
          ))}
          &lt;div className=&quot;mt-auto&quot;&gt;
            &lt;div className=&quot;w-10 h-10 bg-red-500 rounded-full flex items-center justify-center&quot;&gt;
              &lt;span className=&quot;text-white font-bold&quot;&gt;C&lt;/span&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        &lt;/aside&gt;
      );
    }
    function Header(){
      return (
        &lt;header className=&quot;relative bg-gradient-to-br from-teal-900 via-purple-900 to-indigo-900 rounded-xl p-8 mb-6 shadow-2xl&quot;&gt;
          &lt;div className=&quot;absolute inset-0 bg-black opacity-30 rounded-xl&quot;&gt;&lt;/div&gt;
          &lt;div className=&quot;relative z-10 text-center&quot;&gt;
            &lt;div className=&quot;inline-block bg-purple-500 text-white text-sm font-bold px-4 py-1 rounded-full mb-4&quot;&gt;FILM PRODUCTION&lt;/div&gt;
            &lt;h1 className=&quot;text-4xl md:text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-purple-400 mb-6&quot;&gt;NarratingOS Studio Platform&lt;/h1&gt;
            &lt;button data-target=&quot;flow:onboard&quot; className=&quot;bg-transparent border border-purple-500 text-purple-500 px-6 py-3 rounded-full font-semibold flex items-center mx-auto mb-6&quot;&gt;
              &lt;i className=&quot;fas fa-film mr-2&quot;&gt;&lt;/i&gt; Start Creating Your Story
            &lt;/button&gt;
            &lt;div className=&quot;flex justify-center space-x-4 mb-6&quot;&gt;
              &lt;button data-target=&quot;tab=projects&quot; className=&quot;bg-transparent border border-gray-500 text-gray-300 px-4 py-2 rounded-full flex items-center&quot;&gt;&lt;i className=&quot;fas fa-folder mr-2&quot;&gt;&lt;/i&gt;Your projects&lt;/button&gt;
              &lt;button data-target=&quot;open:templates&quot; className=&quot;bg-purple-500 text-white px-4 py-2 rounded-full flex items-center&quot;&gt;&lt;i className=&quot;fas fa-film mr-2&quot;&gt;&lt;/i&gt;Modules&lt;/button&gt;
              &lt;button data-target=&quot;open:ai&quot; className=&quot;bg-transparent border border-gray-500 text-gray-300 px-4 py-2 rounded-full flex items-center&quot;&gt;&lt;i className=&quot;fas fa-robot mr-2&quot;&gt;&lt;/i&gt;AI Assistant&lt;/button&gt;
            &lt;/div&gt;
            &lt;div className=&quot;max-w-2xl mx-auto relative&quot;&gt;
              &lt;div className=&quot;absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none&quot;&gt;&lt;i className=&quot;fas fa-search text-gray-400&quot;&gt;&lt;/i&gt;&lt;/div&gt;
              &lt;input type=&quot;text&quot; placeholder=&quot;Search film production modules and templates&quot; className=&quot;w-full pl-10 pr-4 py-3 bg-transparent border border-gray-500 rounded-full focus:outline-none focus:ring-2 focus:ring-purple-500&quot;/&gt;
              &lt;button className=&quot;absolute inset-y-0 right-0 pr-3 flex items-center&quot;&gt;&lt;i className=&quot;fas fa-arrow-right text-gray-400&quot;&gt;&lt;/i&gt;&lt;/button&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        &lt;/header&gt;
      );
    }
    function ModulesGrid(){
      return (
        &lt;div className=&quot;flex flex-wrap gap-4 justify-center mb-8&quot;&gt;
          {modules.map(([id,icon,label,bg],i)=&gt;(
            &lt;button key={id} data-target={`module:${id}`} className={`flex flex-col items-center p-3 ${bg} rounded-full hover:opacity-90 transition-colors duration-200`}&gt;
              &lt;div className=&quot;w-12 h-12 bg-white rounded-full flex items-center justify-center mb-1&quot;&gt;&lt;i className={`fas fa-${icon} text-${bg ? &apos;&apos; : &apos;&apos;}`}&gt;&lt;/i&gt;&lt;/div&gt;
              &lt;span className=&quot;text-sm&quot;&gt;{label}&lt;/span&gt;
            &lt;/button&gt;
          ))}
        &lt;/div&gt;
      );
    }
    function Releases(){
      return (
        &lt;section className=&quot;mb-8&quot;&gt;
          &lt;h2 className=&quot;text-xl font-bold mb-4&quot;&gt;Latest content releases from our platform&lt;/h2&gt;
          &lt;div className=&quot;grid grid-cols-1 md:grid-cols-3 gap-4&quot;&gt;
            {releases.map((r,i)=&gt;(
              &lt;div key={i} className=&quot;p-4 rounded-lg&quot; style={{background:`linear-gradient(135deg,#1e3a8a,#7c3aed)`}}&gt;
                &lt;h3 className=&quot;text-white font-medium mb-2&quot;&gt;{r.title}&lt;/h3&gt;
                &lt;img src={r.img} alt=&quot;&quot; className=&quot;w-full h-32 object-cover rounded-md&quot;/&gt;
                &lt;p className=&quot;text-gray-200 text-xs mt-2&quot;&gt;{r.meta}&lt;/p&gt;
              &lt;/div&gt;
            ))}
          &lt;/div&gt;
        &lt;/section&gt;
      );
    }
    function RecentWorks(){
      const items = window.mockRecent || [];
      return (
        &lt;section className=&quot;mb-8&quot;&gt;
          &lt;div className=&quot;flex justify-between items-center mb-4&quot;&gt;&lt;h2 className=&quot;text-xl font-bold&quot;&gt;Recent works&lt;/h2&gt;&lt;button className=&quot;bg-gray-800 hover:bg-gray-700 p-2 rounded-lg&quot;&gt;&lt;i className=&quot;fas fa-ellipsis-h&quot;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;
          &lt;div className=&quot;grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4&quot;&gt;
            {items.map((it,idx)=&gt;(
              &lt;article key={idx} className=&quot;bg-gray-800 rounded-lg overflow-hidden transition-transform duration-300 hover:scale-105&quot;&gt;
                &lt;div className=&quot;aspect-video bg-gray-900&quot;&gt;&lt;img src=&quot;https://via.placeholder.com/300x200&quot; alt=&quot;&quot; className=&quot;w-full h-full object-cover&quot;/&gt;&lt;/div&gt;
                &lt;div className=&quot;p-3&quot;&gt;&lt;h3 className=&quot;font-medium text-sm&quot;&gt;{it.title}&lt;/h3&gt;&lt;p className=&quot;text-gray-400 text-xs mt-1&quot;&gt;{it.meta}&lt;/p&gt;&lt;/div&gt;
              &lt;/article&gt;
            ))}
          &lt;/div&gt;
        &lt;/section&gt;
      );
    }
    function Modals(){
      return (
        &lt;&gt;
          &lt;div id=&quot;headerModal&quot; className=&quot;fixed inset-0 bg-black bg-opacity-50 z-50 hidden&quot;&gt;
            &lt;div className=&quot;fixed inset-4 bg-gray-900 rounded-xl shadow-2xl overflow-hidden flex&quot;&gt;
              &lt;aside className=&quot;w-full bg-gradient-to-br from-teal-900 via-purple-900 to-indigo-900 p-8 relative&quot;&gt;
                &lt;div className=&quot;absolute inset-0 bg-black opacity-30 rounded-xl&quot;&gt;&lt;/div&gt;
                &lt;button data-action=&quot;toggleHeaderModal&quot; className=&quot;absolute top-6 right-6 text-white hover:text-gray-300 z-20&quot;&gt;&lt;i className=&quot;fas fa-times text-2xl&quot;&gt;&lt;/i&gt;&lt;/button&gt;
                &lt;div className=&quot;relative z-10 text-center h-full flex flex-col justify-center&quot;&gt;
                  &lt;h1 className=&quot;text-4xl md:text-6xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-purple-400 mb-8&quot;&gt;NarratingOS Studio Platform&lt;/h1&gt;
                  &lt;p className=&quot;text-gray-300 text-lg mb-8 max-w-3xl mx-auto&quot;&gt;Transform your creative vision into reality across scriptwriting to post-production.&lt;/p&gt;
                &lt;/div&gt;
              &lt;/aside&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;div id=&quot;templatesModal&quot; className=&quot;fixed inset-0 bg-black bg-opacity-50 z-50 hidden&quot;&gt;
            &lt;div className=&quot;fixed inset-4 bg-gray-900 rounded-xl shadow-2xl overflow-hidden flex&quot;&gt;
              &lt;button data-action=&quot;toggleTemplates&quot; className=&quot;absolute top-4 right-4 text-gray-400 hover:text-white z-20&quot;&gt;
                &lt;i className=&quot;fas fa-times&quot;&gt;&lt;/i&gt;
              &lt;/button&gt;
              &lt;aside className=&quot;w-80 bg-gradient-to-br from-purple-900 via-indigo-900 to-blue-900 p-6 border-r border-gray-700 flex flex-col&quot;&gt;
                &lt;h1 className=&quot;text-2xl font-bold text-white mb-2&quot;&gt;Templates&lt;/h1&gt;
                &lt;input placeholder=&quot;Search templates...&quot; className=&quot;bg-gray-800 text-white px-4 py-3 rounded-lg w-full focus:outline-none mb-4&quot;/&gt;
                &lt;nav className=&quot;space-y-2&quot;&gt;&lt;button className=&quot;w-full text-left py-3 px-4 text-purple-400 bg-purple-900 bg-opacity-50 rounded-lg&quot;&gt;All Templates&lt;/button&gt;&lt;/nav&gt;
              &lt;/aside&gt;
              &lt;div className=&quot;flex-1 p-6 overflow-auto&quot;&gt;
                &lt;div className=&quot;mb-8&quot;&gt;
                  &lt;div className=&quot;flex items-center justify-between mb-4&quot;&gt;&lt;h2 className=&quot;text-xl font-bold&quot;&gt;Featured Film Templates&lt;/h2&gt;&lt;/div&gt;
                  &lt;div className=&quot;grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6&quot;&gt;
                    &lt;div className=&quot;bg-gray-800 rounded-lg overflow-hidden hover:shadow-xl transition-all duration-300 cursor-pointer&quot;&gt;
                      &lt;div className=&quot;aspect-[3/4] bg-gradient-to-br from-blue-600 to-purple-700 overflow-hidden&quot;&gt;&lt;img src=&quot;https://via.placeholder.com/300x400/2563EB/FFFFFF?text=Sci-Fi+Storyboard&quot; alt=&quot;&quot; className=&quot;w-full h-full object-cover&quot;/&gt;&lt;/div&gt;
                      &lt;div className=&quot;p-4&quot;&gt;&lt;h3 className=&quot;font-medium text-sm mb-1&quot;&gt;Sci-Fi Storyboard Template&lt;/h3&gt;&lt;p className=&quot;text-gray-400 text-xs&quot;&gt;Perfect for futuristic storylines&lt;/p&gt;&lt;/div&gt;
                    &lt;/div&gt;
                  &lt;/div&gt;
                &lt;/div&gt;
              &lt;/div&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;div id=&quot;notificationsModal&quot; className=&quot;fixed inset-0 bg-black bg-opacity-50 z-50 hidden&quot;&gt;
            &lt;div className=&quot;fixed left-20 top-0 h-full w-80 bg-gray-800 shadow-xl&quot;&gt;
              &lt;div className=&quot;flex items-center justify-between p-4 border-b border-gray-700&quot;&gt;
                &lt;h2 className=&quot;text-white text-lg font-semibold&quot;&gt;Notifications&lt;/h2&gt;
                &lt;button data-action=&quot;markAllAsRead&quot; className=&quot;text-blue-400 text-sm hover:text-blue-300&quot;&gt;Mark all as read&lt;/button&gt;
              &lt;/div&gt;
              &lt;div className=&quot;overflow-y-auto h-full pb-20&quot;&gt;
                &lt;div className=&quot;flex items-start p-4 border-b border-gray-700 hover:bg-gray-700 transition-colors&quot;&gt;
                  &lt;div className=&quot;w-10 h-10 bg-orange-500 rounded-lg flex items-center justify-center mr-3 flex-shrink-0&quot;&gt;
                    &lt;span className=&quot;text-white font-bold text-sm&quot;&gt;C&lt;/span&gt;
                  &lt;/div&gt;
                  &lt;div className=&quot;flex-1&quot;&gt;
                    &lt;div className=&quot;flex items-center mb-1&quot;&gt;&lt;span className=&quot;text-white font-medium text-sm&quot;&gt;CREATIVITY Origins created a new Brand Kit.&lt;/span&gt;&lt;div className=&quot;w-2 h-2 bg-red-500 rounded-full ml-2&quot;&gt;&lt;/div&gt;&lt;/div&gt;
                    &lt;div className=&quot;flex items-center text-gray-400 text-xs&quot;&gt;&lt;i className=&quot;fas fa-clock mr-1&quot;&gt;&lt;/i&gt;&lt;span&gt;8:39 PM, Aug 18&lt;/span&gt;&lt;/div&gt;
                  &lt;/div&gt;
                &lt;/div&gt;
              &lt;/div&gt;
              &lt;button data-action=&quot;toggleNotifications&quot; className=&quot;absolute top-4 right-4 text-gray-400 hover:text-white&quot;&gt;&lt;i className=&quot;fas fa-times&quot;&gt;&lt;/i&gt;&lt;/button&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        &lt;/&gt;
      );
    }
    function DashboardUI(){
      useEffect(()=&gt;{
        if(window.setupDashboardUI) window.setupDashboardUI();
        if(window.feather) window.feather.replace();
      },[]);
      return (
        &lt;div className=&quot;ml-20 pt-4 pb-10 px-6&quot;&gt;
          &lt;Header /&gt;
          &lt;ModulesGrid /&gt;
          &lt;Releases /&gt;
          &lt;RecentWorks /&gt;
        &lt;/div&gt;
      );
    }
    // Projects page (static dashboard built from user&apos;s snippet)
    function ProjectsPage(){
      return (
        &lt;div className=&quot;ml-20 pt-4 pb-10 px-6&quot;&gt;
          {/* Search Bar (moved above header) */}
          &lt;div className=&quot;relative mt-4 mx-4 mb-6&quot;&gt;
            &lt;div className=&quot;absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none&quot;&gt;
              &lt;i className=&quot;fas fa-search text-gray-400&quot;&gt;&lt;/i&gt;
            &lt;/div&gt;
            &lt;input type=&quot;text&quot; placeholder=&quot;Search designs, folders, and uploads&quot; className=&quot;w-full pl-10 pr-4 py-3 bg-transparent border border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500&quot; /&gt;
          &lt;/div&gt;
          {/* Header Section */}
          &lt;div className=&quot;relative mb-6 h-80&quot;&gt;
            &lt;div className=&quot;absolute inset-0 bg-gradient-to-r from-teal-800 to-blue-800 rounded-xl overflow-hidden&quot;&gt;
              &lt;img src=&quot;https://via.placeholder.com/1200x300&quot; alt=&quot;Background&quot; className=&quot;w-full h-full object-cover opacity-70&quot; /&gt;
              &lt;div className=&quot;absolute inset-0 flex items-center justify-center&quot;&gt;
                &lt;div className=&quot;text-center&quot;&gt;
                  &lt;h1 className=&quot;text-4xl font-bold text-white&quot;&gt;Projects&lt;/h1&gt;
                  &lt;div className=&quot;mt-4&quot;&gt;
                    &lt;svg width=&quot;120&quot; height=&quot;120&quot; viewBox=&quot;0 0 120 120&quot; fill=&quot;none&quot; xmlns=&quot;http://www.w3.org/2000/svg&quot;&gt;
                      &lt;rect x=&quot;20&quot; y=&quot;20&quot; width=&quot;80&quot; height=&quot;80&quot; rx=&quot;12&quot; fill=&quot;#3B82F6&quot; stroke=&quot;white&quot; strokeWidth=&quot;2&quot;/&gt;
                      &lt;rect x=&quot;20&quot; y=&quot;20&quot; width=&quot;80&quot; height=&quot;80&quot; rx=&quot;12&quot; fill=&quot;url(#gradient)&quot; /&gt;
                      &lt;rect x=&quot;30&quot; y=&quot;30&quot; width=&quot;60&quot; height=&quot;60&quot; rx=&quot;10&quot; fill=&quot;white&quot; opacity=&quot;0.2&quot;/&gt;
                      &lt;rect x=&quot;35&quot; y=&quot;35&quot; width=&quot;50&quot; height=&quot;50&quot; rx=&quot;8&quot; fill=&quot;white&quot; opacity=&quot;0.4&quot;/&gt;
                      &lt;rect x=&quot;40&quot; y=&quot;40&quot; width=&quot;40&quot; height=&quot;40&quot; rx=&quot;6&quot; fill=&quot;white&quot; opacity=&quot;0.6&quot;/&gt;
                      &lt;rect x=&quot;45&quot; y=&quot;45&quot; width=&quot;30&quot; height=&quot;30&quot; rx=&quot;4&quot; fill=&quot;white&quot; opacity=&quot;0.8&quot;/&gt;
                      &lt;rect x=&quot;50&quot; y=&quot;50&quot; width=&quot;20&quot; height=&quot;20&quot; rx=&quot;2&quot; fill=&quot;white&quot;/&gt;
                    &lt;/svg&gt;
                  &lt;/div&gt;
                &lt;/div&gt;
              &lt;/div&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          {/* Filter and Sort Controls */}
          &lt;div className=&quot;flex flex-wrap gap-3 justify-between mb-6&quot;&gt;
            &lt;div className=&quot;flex gap-3&quot;&gt;
              &lt;select className=&quot;bg-gray-800 border border-gray-600 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500&quot;&gt;
                &lt;option&gt;Owner&lt;/option&gt;
                &lt;option&gt;My projects&lt;/option&gt;
                &lt;option&gt;Shared with me&lt;/option&gt;
              &lt;/select&gt;
              &lt;select className=&quot;bg-gray-800 border border-gray-600 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500&quot;&gt;
                &lt;option&gt;Category&lt;/option&gt;
                &lt;option&gt;All&lt;/option&gt;
                &lt;option&gt;Designs&lt;/option&gt;
                &lt;option&gt;Images&lt;/option&gt;
                &lt;option&gt;Videos&lt;/option&gt;
              &lt;/select&gt;
              &lt;select className=&quot;bg-gray-800 border border-gray-600 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500&quot;&gt;
                &lt;option&gt;Date modified&lt;/option&gt;
                &lt;option&gt;Newest first&lt;/option&gt;
                &lt;option&gt;Oldest first&lt;/option&gt;
              &lt;/select&gt;
