// Enhanced Writing Canvas Component with Rich Text Editor
const WritingCanvas = ({ activeStory }) =&gt; {
  const { switchSpace } = useApp();
  const [content, setContent] = useState(`&lt;h1&gt;Chapter 1: The Signal&lt;/h1&gt;
&lt;p&gt;The deep space monitoring station orbited silently in the void, its arrays of sensors reaching out into the cosmos like digital tentacles. Alex Mercer floated through the zero-gravity corridors, her magnetic boots clicking against the metal floor plates as she made her way to the communications bay.&lt;/p&gt;
&lt;p&gt;For three years, the station had been humanity&apos;s ear to the universe, listening for any sign that we weren&apos;t alone. And today, that vigil was about to end.&lt;/p&gt;
&lt;p&gt;&lt;em&gt;&quot;Alex, you need to see this,&quot;&lt;/em&gt; Dr. Lena Hayes called from the main console, her voice tight with excitement and something else—fear, perhaps.&lt;/p&gt;
&lt;p&gt;The signal was unlike anything they had recorded before. Not the random cosmic background radiation they were used to, not the predictable pulses of pulsars or the chaotic bursts of solar flares. This was &lt;strong&gt;structured&lt;/strong&gt;, mathematical, deliberate.&lt;/p&gt;
&lt;p&gt;It was a message.&lt;/p&gt;`);
  const [wordCount, setWordCount] = useState(0);
  const [saveStatus, setSaveStatus] = useState(&apos;saved&apos;);
  const [showTransitionMenu, setShowTransitionMenu] = useState(false);
  useEffect(() =&gt; {
    // Count words from HTML content
    const textContent = content.replace(/&lt;[^&gt;]*&gt;/g, &apos;&apos;);
    setWordCount(textContent.split(/\s+/).filter(word =&gt; word.length &gt; 0).length);
    setSaveStatus(&apos;saving...&apos;);
    const timer = setTimeout(() =&gt; {
      setSaveStatus(&apos;saved&apos;);
    }, 1000);
    return () =&gt; clearTimeout(timer);
  }, [content]);
  const handleSendToStoryboard = () =&gt; {
    // Extract scenes from content for storyboard transition
    setShowTransitionMenu(false);
    setTimeout(() =&gt; {
      switchSpace(&apos;Storyboard&apos;);
    }, 300);
  };
  return (
    &lt;div className=&quot;flex-1 flex flex-col p-6&quot;&gt;
      {/* Enhanced Writing Stats Bar */}
      &lt;div className=&quot;flex items-center justify-between mb-4 p-3 bg-muted rounded-lg&quot;&gt;
        &lt;div className=&quot;flex items-center space-x-4 text-sm text-muted-foreground&quot;&gt;
          &lt;span className=&quot;animate-pulse&quot;&gt;{wordCount} words&lt;/span&gt;
          &lt;span&gt;•&lt;/span&gt;
          &lt;span&gt;Chapter 1&lt;/span&gt;
          &lt;span&gt;•&lt;/span&gt;
          &lt;span className=&quot;flex items-center&quot;&gt;
            &lt;Icons.Zap /&gt;
            &lt;span className=&quot;ml-1&quot;&gt;{saveStatus}&lt;/span&gt;
          &lt;/span&gt;
        &lt;/div&gt;
        &lt;div className=&quot;flex items-center space-x-2&quot;&gt;
          &lt;Button variant=&quot;ghost&quot; size=&quot;sm&quot; className=&quot;&quot;&gt;
            &lt;Icons.Eye /&gt;
            &lt;span className=&quot;ml-1&quot;&gt;Focus Mode&lt;/span&gt;
          &lt;/Button&gt;
          &lt;div className=&quot;relative&quot;&gt;
            &lt;Button 
              variant=&quot;ghost&quot; 
              size=&quot;sm&quot; 
              className=&quot;&quot;
              onClick={() =&gt; setShowTransitionMenu(!showTransitionMenu)}
            &gt;
              &lt;Icons.Send /&gt;
              &lt;span className=&quot;ml-1&quot;&gt;Send to...&lt;/span&gt;
            &lt;/Button&gt;
            {showTransitionMenu &amp;&amp; (
              &lt;div className=&quot;absolute right-0 top-full mt-1 w-48 bg-card border rounded-lg shadow-lg z-50 animate-scale-in&quot;&gt;
                &lt;button 
                  className=&quot;w-full text-left px-3 py-2 hover:bg-muted rounded-t-lg cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&quot;
                  onClick={handleSendToStoryboard}
                &gt;
                  &lt;Icons.Film /&gt;
                  &lt;span className=&quot;ml-2&quot;&gt;Storyboard Space&lt;/span&gt;
                &lt;/button&gt;
                &lt;button 
                  className=&quot;w-full text-left px-3 py-2 hover:bg-muted cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&quot;
                  onClick={() =&gt; switchSpace(&apos;Editor&apos;)}
                &gt;
                  &lt;Icons.Edit /&gt;
                  &lt;span className=&quot;ml-2&quot;&gt;Editor Space&lt;/span&gt;
                &lt;/button&gt;
                &lt;button 
                  className=&quot;w-full text-left px-3 py-2 hover:bg-muted rounded-b-lg cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&quot;
                  onClick={() =&gt; setShowTransitionMenu(false)}
                &gt;
                  &lt;Icons.Download /&gt;
                  &lt;span className=&quot;ml-2&quot;&gt;Export&lt;/span&gt;
                &lt;/button&gt;
              &lt;/div&gt;
            )}
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
      {/* Rich Text Writing Area */}
      &lt;div className=&quot;flex-1 bg-card rounded-lg border overflow-hidden&quot;&gt;
        &lt;RichTextEditor 
          value={content}
          onChange={setContent}
          placeholder=&quot;Start writing your story...&quot;
        /&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
