// Enhanced Main App Component with Routing
const App = () =&gt; {
  // Check if routing is available
  if (!window.useRouter) {
    return React.createElement(&apos;div&apos;, { 
      style: { padding: &apos;20px&apos;, textAlign: &apos;center&apos; } 
    },
      React.createElement(&apos;h1&apos;, null, &apos;Loading NarratingOS...&apos;),
      React.createElement(&apos;p&apos;, null, &apos;Routing system not yet available&apos;)
    );
  }
  const { currentRoute, isTransitioning } = window.useRouter();
  const { theme, toggleTheme } = useTheme();
  return (
    &lt;div className=&quot;min-h-screen bg-background text-foreground&quot;&gt;
      &lt;div className=&quot;h-screen flex flex-col overflow-hidden&quot;&gt;
        {/* Header with Navigation */}
        &lt;Header /&gt;
        {/* Top-level Tabs */}
        &lt;TabBar /&gt;
        {/* Main Content Area */}
        &lt;main className=&quot;flex-1 relative overflow-hidden&quot;&gt;
          {/* Transition Overlay */}
          {isTransitioning &amp;&amp; (
            &lt;div className=&quot;absolute inset-0 bg-background/80 flex items-center justify-center z-50 animate-fade-in&quot;&gt;
              &lt;div className=&quot;text-center&quot;&gt;
                &lt;div className=&quot;animate-spin w-8 h-8 border-2 border-primary border-t-transparent rounded-full mx-auto mb-4&quot;&gt;&lt;/div&gt;
                &lt;p className=&quot;text-muted-foreground&quot;&gt;Switching to {currentRoute.name}...&lt;/p&gt;
              &lt;/div&gt;
            &lt;/div&gt;
          )}
          {/* Route Content */}
          &lt;div className=&quot;h-full overflow-auto&quot;&gt;
            {/* Active Routes */}
            {currentRoute.name === &apos;Writing&apos; &amp;&amp; (
              &lt;div className=&quot;h-full p-6&quot;&gt;
                &lt;WritingCanvas /&gt;
                &lt;CharacterGallery /&gt;
              &lt;/div&gt;
            )}
            {currentRoute.name === &apos;Storyboard&apos; &amp;&amp; (
              &lt;div className=&quot;h-full&quot;&gt;
                &lt;StoryboardSpace /&gt;
              &lt;/div&gt;
            )}
            {currentRoute.name === &apos;Editor&apos; &amp;&amp; (
              &lt;div className=&quot;h-full&quot;&gt;
                &lt;EditorSpace /&gt;
              &lt;/div&gt;
            )}
            {/* Coming Soon Routes */}
            {currentRoute.comingSoon &amp;&amp; (
              React.createElement(window.ComingSoonPlaceholder, { route: currentRoute })
            )}
          &lt;/div&gt;
        &lt;/main&gt;
        {/* Collapsible Islands */}
        &lt;SidebarIsland /&gt;
        &lt;AIAssistantIsland /&gt;
        {/* Templates Panel (proto) */}
        {/** Render TemplatesPanel when templatesOpen is true **/}
        &lt;TemplatesPanelPlaceholder /&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
// Minimal Templates Panel placeholder (rendered when templatesOpen is true)
const TemplatesPanelPlaceholder = () =&gt; {
