// --- Application Initialization ---
const container = document.getElementById(&apos;root&apos;);
const root = createRoot(container);
console.log(&apos;About to render app...&apos;, {
  container: !!container,
  root: !!root,
  RouterProvider: !!window.RouterProvider,
  ThemeProvider: !!ThemeProvider,
  CollapsibleProvider: !!CollapsibleProvider,
  AppProvider: !!AppProvider,
  App: !!App
});
// Initialize with RouterProvider - ensure it&apos;s available
if (!window.RouterProvider) {
  console.error(&apos;RouterProvider not available! Route.js may not have loaded properly.&apos;);
  // Fallback rendering without router for debugging
  root.render(
    React.createElement(&apos;div&apos;, { 
      style: { 
        padding: &apos;20px&apos;, 
        fontFamily: &apos;Arial, sans-serif&apos;,
        background: &apos;#f8f9fa&apos;,
        minHeight: &apos;100vh&apos;
      } 
    },
      React.createElement(&apos;h1&apos;, { style: { color: &apos;#333&apos; } }, &apos;NarratingOS&apos;),
      React.createElement(&apos;p&apos;, null, &apos;RouterProvider not available - Route.js may not have loaded&apos;),
      React.createElement(&apos;p&apos;, null, &apos;Check the browser console for more details&apos;)
    )
  );
} else {
  console.log(&apos;RouterProvider is available, attempting full app render...&apos;);
  try {
    root.render(
      React.createElement(ThemeProvider, null,
        React.createElement(CollapsibleProvider, null,
          React.createElement(window.RouterProvider, null,
            React.createElement(AppProvider, null,
              React.createElement(App, null)
            )
          )
        )
      )
    );
    console.log(&apos;App rendered successfully!&apos;);
  } catch (error) {
    console.error(&apos;Error rendering full app:&apos;, error);
    // Fallback to basic app
    root.render(
      React.createElement(&apos;div&apos;, { style: { padding: &apos;20px&apos; } },
        React.createElement(&apos;h1&apos;, null, &apos;NarratingOS - Error&apos;),
        React.createElement(&apos;p&apos;, null, &apos;Error rendering app: &apos; + error.message)
      )
    );
  }
}
// Initialize feather icons and setup animations
setTimeout(() =&gt; {
  if (window.feather) {
    window.feather.replace();
  }
  // Add entrance animations to initial elements
  if (window.anime) {
    window.anime({
      targets: &apos;.animate-slide-down&apos;,
      translateY: [-20, 0],
      opacity: [0, 1],
      duration: 800,
      easing: &apos;easeOutCubic&apos;
    });
  }
}, 100);
