  { id: 'tab2', name: 'story.md', type: 'file' as const, isDirty: true, path: '/docs/story.md', extension: 'md' },
  { id: 'tab3', name: 'screenplay.fountain', type: 'file' as const, isDirty: false, path: '/scripts/screenplay.fountain', extension: 'fountain' },
  { id: 'tab4', name: 'Untitled-1', type: 'untitled' as const, isDirty: true }
];
export default function EditorTabsExample() {
  const [tabs, setTabs] = useState(mockTabs);
  const [activeTab, setActiveTab] = useState('tab2');
  const handleTabSelect = (tabId: string) => {
    setActiveTab(tabId);
  };
  const handleTabClose = (tabId: string) => {
    setTabs(prev => prev.filter(tab => tab.id !== tabId));
    if (activeTab === tabId && tabs.length > 1) {
      const remainingTabs = tabs.filter(tab => tab.id !== tabId);
      setActiveTab(remainingTabs[0]?.id || '');
    }
  };
  const handleTabSave = (tabId: string) => {
    setTabs(prev => prev.map(tab => 
      tab.id === tabId ? { ...tab, isDirty: false } : tab
    ));
  };
  return (
    <div className="h-32 bg-background">
      <EditorTabs
        tabs={tabs}
        activeTabId={activeTab}
        onTabSelect={handleTabSelect}
        onTabClose={handleTabClose}
        onTabSave={handleTabSave}
      />
    </div>
  );
}import { useState } from 'react';
