}import { useState, useRef, useEffect } from 'react';
import { Search, Replace, Download, Copy, Maximize2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { 
  DropdownMenu, 
  DropdownMenuContent, 
  DropdownMenuItem, 
  DropdownMenuTrigger 
} from '@/components/ui/dropdown-menu';
interface CodeEditorProps {
  content: string;
  language: string;
  onChange: (content: string) => void;
  onSave?: () => void;
  fileName?: string;
  readOnly?: boolean;
}
export function CodeEditor({ 
  content, 
  language, 
  onChange, 
  onSave, 
  fileName = 'untitled',
  readOnly = false 
}: CodeEditorProps) {
  const [localContent, setLocalContent] = useState(content);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSearch, setShowSearch] = useState(false);
  const [lineNumbers, setLineNumbers] = useState<number[]>([]);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  useEffect(() => {
    setLocalContent(content);
  }, [content]);
  useEffect(() => {
    const lines = localContent.split('\n');
    setLineNumbers(Array.from({ length: lines.length }, (_, i) => i + 1));
  }, [localContent]);
  const handleContentChange = (newContent: string) => {
    setLocalContent(newContent);
    onChange(newContent);
  };
  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Save shortcut
    if (e.ctrlKey && e.key === 's') {
      e.preventDefault();
      console.log('Save triggered');
      onSave?.();
    }
    // Search shortcut
    if (e.ctrlKey && e.key === 'f') {
      e.preventDefault();
      setShowSearch(true);
    }
    // Tab handling
    if (e.key === 'Tab') {
      e.preventDefault();
      const textarea = e.target as HTMLTextAreaElement;
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const newContent = localContent.substring(0, start) + '  ' + localContent.substring(end);
      handleContentChange(newContent);
      // Set cursor position after tab
      setTimeout(() => {
        textarea.selectionStart = textarea.selectionEnd = start + 2;
      });
    }
  };
  const copyToClipboard = () => {
    navigator.clipboard.writeText(localContent);
    console.log('Content copied to clipboard');
  };
  const downloadFile = () => {
    const blob = new Blob([localContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    a.click();
    URL.revokeObjectURL(url);
    console.log('File downloaded');
  };
  return (
    <div className="flex flex-col h-full bg-background">
      {/* Editor Header */}
      <div className="flex items-center justify-between px-4 py-2 border-b border-border bg-muted/20">
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium">{fileName}</span>
          <span className="text-xs text-muted-foreground">({language})</span>
        </div>
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="w-7 h-7"
            onClick={() => setShowSearch(!showSearch)}
            data-testid="toggle-search"
          >
            <Search className="w-4 h-4" />
          </Button>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" size="icon" className="w-7 h-7" data-testid="editor-actions">
                <Maximize2 className="w-4 h-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent>
              <DropdownMenuItem onClick={copyToClipboard}>
                <Copy className="w-4 h-4 mr-2" />
                Copy All
              </DropdownMenuItem>
              <DropdownMenuItem onClick={downloadFile}>
                <Download className="w-4 h-4 mr-2" />
                Download
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>
      {/* Search Bar */}
      {showSearch && (
        <div className="flex items-center gap-2 px-4 py-2 bg-muted/30 border-b border-border">
          <Input
            placeholder="Find..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="flex-1 h-7"
            data-testid="search-input"
          />
          <Button variant="ghost" size="icon" className="w-7 h-7">
            <Replace className="w-4 h-4" />
          </Button>
          <Button 
            variant="ghost" 
            size="icon" 
            className="w-7 h-7"
            onClick={() => setShowSearch(false)}
          >
            ×
          </Button>
        </div>
      )}
      {/* Editor Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Line Numbers */}
        <div className="bg-muted/20 px-2 py-4 text-right border-r border-border min-w-12">
          {lineNumbers.map((num) => (
            <div key={num} className="text-xs text-muted-foreground leading-6 font-mono">
              {num}
            </div>
          ))}
        </div>
        {/* Text Area */}
        <div className="flex-1 relative">
          <textarea
            ref={textareaRef}
            value={localContent}
            onChange={(e) => handleContentChange(e.target.value)}
            onKeyDown={handleKeyDown}
            className="w-full h-full resize-none border-0 bg-transparent p-4 font-mono text-sm leading-6 focus:outline-none"
            placeholder={readOnly ? '' : 'Start writing...'}
            readOnly={readOnly}
            data-testid="code-textarea"
            spellCheck={false}
          />
        </div>
      </div>
    </div>
  );
}import { useState } from 'react';
import { X, Circle, File, FileText, Code } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area';
interface EditorTab {
  id: string;
  name: string;
  type: 'file' | 'untitled';
  isDirty: boolean;
  path?: string;
  extension?: string;
}
interface EditorTabsProps {
  tabs: EditorTab[];
  activeTabId: string;
  onTabSelect: (tabId: string) => void;
  onTabClose: (tabId: string) => void;
  onTabSave: (tabId: string) => void;
}
const getFileIcon = (extension?: string) => {
  switch (extension) {
    case 'md':
    case 'markdown':
      return FileText;
    case 'js':
    case 'ts':
    case 'jsx':
    case 'tsx':
      return Code;
    default:
      return File;
  }
};
export function EditorTabs({ tabs, activeTabId, onTabSelect, onTabClose, onTabSave }: EditorTabsProps) {
  const [draggedTab, setDraggedTab] = useState<string | null>(null);
  const handleTabClick = (tabId: string) => {
    console.log(`Switching to tab: ${tabId}`);
    onTabSelect(tabId);
  };
  const handleTabClose = (e: React.MouseEvent, tabId: string) => {
    e.stopPropagation();
    console.log(`Closing tab: ${tabId}`);
    onTabClose(tabId);
  };
  const handleSaveShortcut = (e: React.KeyboardEvent, tabId: string) => {
    if (e.ctrlKey && e.key === 's') {
      e.preventDefault();
      onTabSave(tabId);
    }
  };
  return (
    <div className="bg-background border-b border-border">
      <ScrollArea className="w-full">
        <div className="flex">
          {tabs.map((tab) => {
            const isActive = tab.id === activeTabId;
            const Icon = getFileIcon(tab.extension);
            return (
              <div
                key={tab.id}
                className={`
                  flex items-center gap-2 px-4 py-2.5 min-w-32 max-w-48 cursor-pointer
                  border-r border-border/50 hover:bg-muted/50 transition-colors relative
                  ${isActive ? 'bg-background text-foreground border-b-2 border-b-primary' : 'bg-muted/20 text-muted-foreground'}
                  ${draggedTab === tab.id ? 'opacity-50' : ''}
                `}
                onClick={() => handleTabClick(tab.id)}
                onKeyDown={(e) => handleSaveShortcut(e, tab.id)}
                data-testid={`tab-${tab.id}`}
                draggable
                onDragStart={() => setDraggedTab(tab.id)}
                onDragEnd={() => setDraggedTab(null)}
              >
                <Icon className="w-4 h-4 flex-shrink-0" />
                <span className="truncate text-sm flex-1">
                  {tab.name}
                </span>
                {tab.isDirty && (
                  <Circle className="w-2 h-2 fill-current text-accent flex-shrink-0" />
                )}
                <Button
                  variant="ghost"
                  size="icon"
                  className="w-4 h-4 p-0 opacity-0 group-hover:opacity-100 hover:bg-muted"
                  onClick={(e) => handleTabClose(e, tab.id)}
                  data-testid={`close-tab-${tab.id}`}
                >
                  <X className="w-3 h-3" />
                </Button>
              </div>
            );
          })}
        </div>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>
    </div>
  );
}import { useState } from 'react';
import { ChevronDown, ChevronRight, File, Folder, FolderOpen, Plus, MoreHorizontal, Eye } from 'lucide-react';
