  onFileCreate, 
  onFileRename, 
  onFileDelete,
  onFilePreview,
  selectedFileId 
}: FileExplorerProps) {
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['root']));
  const [editingFile, setEditingFile] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const toggleFolder = (folderId: string) => {
    const newExpanded = new Set(expandedFolders);
    if (newExpanded.has(folderId)) {
      newExpanded.delete(folderId);
    } else {
      newExpanded.add(folderId);
    }
    setExpandedFolders(newExpanded);
  };
  const handleRename = (file: FileNode) => {
    setEditingFile(file.id);
    setEditValue(file.name);
  };
  const handleRenameSubmit = (fileId: string) => {
    if (editValue.trim()) {
      onFileRename(fileId, editValue.trim());
    }
    setEditingFile(null);
    setEditValue('');
  };
  const renderFileNode = (node: FileNode, depth = 0) => {
    const isFolder = node.type === 'folder';
    const isExpanded = expandedFolders.has(node.id);
    const isSelected = selectedFileId === node.id;
    const isEditing = editingFile === node.id;
    return (
      <div key={node.id}>
        <div 
          className={`flex items-center gap-2 px-2 py-1.5 text-sm cursor-pointer hover:bg-sidebar-accent/20 transition-colors ${
            isSelected ? 'bg-sidebar-accent/30' : ''
          }`}
          style={{ paddingLeft: `${8 + depth * 16}px` }}
          data-testid={`file-${node.id}`}
        >
          {isFolder && (
            <Button
              variant="ghost"
              size="icon"
              className="w-4 h-4 p-0"
              onClick={() => toggleFolder(node.id)}
              data-testid={`folder-toggle-${node.id}`}
            >
              {isExpanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
            </Button>
          )}
          {!isFolder && <div className="w-4" />}
          <div className="w-4 h-4 flex items-center justify-center">
            {isFolder ? (
              isExpanded ? <FolderOpen className="w-4 h-4 text-primary" /> : <Folder className="w-4 h-4 text-primary" />
            ) : (
              <File className="w-4 h-4 text-muted-foreground" />
            )}
          </div>
          {isEditing ? (
            <Input
              value={editValue}
              onChange={(e) => setEditValue(e.target.value)}
              onBlur={() => handleRenameSubmit(node.id)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit(node.id);
                if (e.key === 'Escape') setEditingFile(null);
              }}
              className="h-6 text-sm bg-background"
              autoFocus
              data-testid={`rename-input-${node.id}`}
            />
          ) : (
            <span 
              className="flex-1 truncate"
              onClick={() => {
                console.log(`Selected file: ${node.name}`);
                onFileSelect(node);
              }}
            >
              {node.name}
            </span>
          )}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="w-4 h-4 p-0 opacity-0 group-hover:opacity-100"
                data-testid={`file-menu-${node.id}`}
              >
                <MoreHorizontal className="w-3 h-3" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent>
              {!isFolder && (
                <DropdownMenuItem 
                  onClick={() => {
                    console.log(`Opening preview for: ${node.name}`);
                    onFilePreview(node);
                  }}
                  data-testid={`preview-${node.id}`}
                >
                  <Eye className="w-3 h-3 mr-2" />
                  Preview
                </DropdownMenuItem>
              )}
              <DropdownMenuItem onClick={() => handleRename(node)}>
                Rename
              </DropdownMenuItem>
              <DropdownMenuItem 
                onClick={() => {
                  console.log(`Deleting file: ${node.name}`);
                  onFileDelete(node.id);
                }}
                className="text-destructive"
              >
                Delete
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
        {isFolder && isExpanded && node.children && (
          <div>
            {node.children.map(child => renderFileNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };
  return (
    <div className="w-64 bg-sidebar border-r border-sidebar-border flex flex-col h-full">
      {/* Header */}
      <div className="flex items-center justify-between p-3 border-b border-sidebar-border">
        <h2 className="text-sm font-medium text-sidebar-foreground">EXPLORER</h2>
        <div className="flex gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="w-5 h-5 p-0"
            onClick={() => {
              console.log('Creating new file');
              onFileCreate(null, 'file');
            }}
            data-testid="create-file"
          >
            <Plus className="w-3 h-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="w-5 h-5 p-0"
            onClick={() => {
              console.log('Creating new folder');
              onFileCreate(null, 'folder');
            }}
            data-testid="create-folder"
          >
            <Folder className="w-3 h-3" />
          </Button>
        </div>
      </div>
      {/* File Tree */}
      <div className="flex-1 overflow-y-auto py-2">
        <div className="space-y-1">
          {files.map(file => renderFileNode(file))}
        </div>
      </div>
    </div>
  );
}import { useState } from 'react';
import { Eye, EyeOff, ExternalLink, RefreshCw, Download } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
interface PreviewPaneProps {
  content: string;
  language: string;
  fileName: string;
}
export function PreviewPane({ content, language, fileName }: PreviewPaneProps) {
  const [isVisible, setIsVisible] = useState(true);
  const [activeTab, setActiveTab] = useState('preview');
  const renderMarkdown = (text: string) => {
    // Simple markdown renderer for demo
    return text
      .replace(/^### (.*$)/gim, '<h3 class="text-lg font-semibold mt-4 mb-2">$1</h3>')
      .replace(/^## (.*$)/gim, '<h2 class="text-xl font-semibold mt-6 mb-3">$1</h2>')
      .replace(/^# (.*$)/gim, '<h1 class="text-2xl font-bold mt-8 mb-4">$1</h1>')
      .replace(/\*\*(.*)\*\*/gim, '<strong class="font-semibold">$1</strong>')
      .replace(/\*(.*)\*/gim, '<em class="italic">$1</em>')
      .replace(/`([^`]+)`/gim, '<code class="bg-muted px-1 py-0.5 rounded text-sm font-mono">$1</code>')
      .replace(/\n/gim, '<br>');
  };
  const renderScreenplay = (text: string) => {
    // Simple screenplay formatter for demo
    const lines = text.split('\n');
    return lines.map((line, index) => {
      if (line.trim().toUpperCase() === line.trim() && line.trim().length > 0) {
        return `<div key="${index}" class="font-bold text-center my-4 uppercase">${line}</div>`;
      }
      if (line.trim().startsWith('(') && line.trim().endsWith(')')) {
        return `<div key="${index}" class="italic text-center my-2 text-muted-foreground">${line}</div>`;
      }
      if (line.trim().length === 0) {
        return `<div key="${index}" class="h-4"></div>`;
      }
      return `<div key="${index}" class="my-2">${line}</div>`;
    }).join('');
  };
  const getPreviewContent = () => {
    if (!content.trim()) {
      return '<div class="text-muted-foreground italic p-8 text-center">No content to preview</div>';
    }
    switch (language.toLowerCase()) {
      case 'markdown':
      case 'md':
        return renderMarkdown(content);
      case 'screenplay':
      case 'fountain':
        return renderScreenplay(content);
      default:
        return `<pre class="font-mono text-sm whitespace-pre-wrap p-4">${content}</pre>`;
    }
  };
  const exportAsHtml = () => {
    const htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <title>${fileName}</title>
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, sans-serif; max-width: 800px; margin: 0 auto; padding: 2rem; }
    h1, h2, h3 { color: #333; }
    code { background: #f5f5f5; padding: 2px 4px; border-radius: 3px; }
  </style>
</head>
<body>
  ${getPreviewContent()}
</body>
</html>`;
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName.replace(/\.[^/.]+$/, '')}.html`;
    a.click();
    URL.revokeObjectURL(url);
    console.log('HTML exported');
  };
  if (!isVisible) {
    return (
      <div className="w-8 bg-sidebar border-l border-sidebar-border flex flex-col items-center py-2">
        <Button
          variant="ghost"
          size="icon"
          className="w-6 h-6"
          onClick={() => setIsVisible(true)}
          data-testid="show-preview"
        >
          <Eye className="w-4 h-4" />
        </Button>
      </div>
    );
  }
  return (
    <div className="w-96 bg-background border-l border-border flex flex-col h-full">
      {/* Header */}
      <div className="flex items-center justify-between p-3 border-b border-border">
        <h3 className="text-sm font-medium">Preview</h3>
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="w-6 h-6"
            onClick={() => console.log('Refresh preview')}
            data-testid="refresh-preview"
          >
            <RefreshCw className="w-3 h-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="w-6 h-6"
            onClick={exportAsHtml}
            data-testid="export-preview"
          >
            <Download className="w-3 h-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="w-6 h-6"
            onClick={() => console.log('Open in new tab')}
            data-testid="external-preview"
          >
            <ExternalLink className="w-3 h-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="w-6 h-6"
            onClick={() => setIsVisible(false)}
            data-testid="hide-preview"
          >
            <EyeOff className="w-3 h-3" />
          </Button>
        </div>
      </div>
      {/* Content */}
      <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="preview" data-testid="preview-tab">Preview</TabsTrigger>
          <TabsTrigger value="raw" data-testid="raw-tab">Raw</TabsTrigger>
        </TabsList>
        <TabsContent value="preview" className="flex-1 m-0">
          <ScrollArea className="h-full">
            <div 
              className="p-4 prose prose-sm max-w-none"
              dangerouslySetInnerHTML={{ __html: getPreviewContent() }}
              data-testid="preview-content"
            />
          </ScrollArea>
        </TabsContent>
        <TabsContent value="raw" className="flex-1 m-0">
          <ScrollArea className="h-full">
            <pre className="p-4 text-sm font-mono whitespace-pre-wrap" data-testid="raw-content">
              {content}
            </pre>
          </ScrollArea>
        </TabsContent>
      </Tabs>
    </div>
  );
}import { useState, useRef, useCallback, ReactNode } from 'react';
interface ResizablePanesProps {
  children: ReactNode[];
  className?: string;
  minSizes?: number[];
  defaultSizes?: number[];
  direction?: 'horizontal' | 'vertical';
}
export function ResizablePanes({ 
  children, 
  className = '',
  minSizes = [],
  defaultSizes = [],
  direction = 'horizontal'
}: ResizablePanesProps) {
  const [sizes, setSizes] = useState<number[]>(() => {
    if (defaultSizes.length === children.length) {
      return defaultSizes;
    }
    const defaultSize = 100 / children.length;
    return Array(children.length).fill(defaultSize);
  });
  const [isDragging, setIsDragging] = useState(false);
  const [dragIndex, setDragIndex] = useState(-1);
  const containerRef = useRef<HTMLDivElement>(null);
  const handleMouseDown = useCallback((index: number) => (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDragging(true);
    setDragIndex(index);
    const handleMouseMove = (e: MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const total = direction === 'horizontal' ? rect.width : rect.height;
      const pos = direction === 'horizontal' ? e.clientX - rect.left : e.clientY - rect.top;
      const percentage = (pos / total) * 100;
      setSizes(prev => {
        const newSizes = [...prev];
        const minSize = minSizes[index] || 10;
        const minSizeNext = minSizes[index + 1] || 10;
        // Calculate the combined size of the two panes being resized
        const combinedSize = newSizes[index] + newSizes[index + 1];
        // Ensure minimum sizes are respected
        const newFirst = Math.max(minSize, Math.min(combinedSize - minSizeNext, percentage));
        const newSecond = combinedSize - newFirst;
        newSizes[index] = newFirst;
        newSizes[index + 1] = newSecond;
        return newSizes;
      });
    };
    const handleMouseUp = () => {
      setIsDragging(false);
      setDragIndex(-1);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  }, [direction, minSizes]);
  const isHorizontal = direction === 'horizontal';
  return (
    <div 
      ref={containerRef}
      className={`flex ${isHorizontal ? 'flex-row' : 'flex-col'} h-full w-full ${className}`}
      style={{ userSelect: isDragging ? 'none' : 'auto' }}
    >
      {children.map((child, index) => (
        <div key={`fragment-${index}`} className="contents">
          <div
            className="overflow-hidden"
            style={{
              [isHorizontal ? 'width' : 'height']: `${sizes[index]}%`,
              [isHorizontal ? 'height' : 'width']: '100%'
            }}
          >
            {child}
          </div>
          {index < children.length - 1 && (
            <div
              className={`
                ${isHorizontal ? 'w-1 h-full cursor-col-resize' : 'h-1 w-full cursor-row-resize'}
                bg-border hover:bg-primary/50 transition-colors flex-shrink-0
                ${isDragging && dragIndex === index ? 'bg-primary' : ''}
              `}
              onMouseDown={handleMouseDown(index)}
              data-testid={`resize-handle-${index}`}
            />
          )}
        </div>
      ))}
    </div>
  );
}import { useState } from 'react';
