const sampleContent = `# Chapter One: The Digital Awakening
In the heart of Silicon Valley, where innovation pulses through fiber optic veins and dreams are coded into reality, **Maya Chen** sat before her triple-monitor setup, fingers dancing across a mechanical keyboard that had seen countless late-night coding sessions.
## The Vision
Maya had always been different from other developers. While her peers obsessed over algorithms and optimization, she saw code as a medium for storytelling. Every function was a character, every loop a plot twist, every bug a dramatic tension waiting to be resolved.
### Character Profile: Maya Chen
- **Age**: 28
- **Background**: CS degree from Stanford, but minored in Creative Writing
- **Personality**: Analytical yet imaginative, detail-oriented but visionary
- **Goal**: To create software that doesn't just solve problems, but tells stories
## The Challenge
The startup world had been unkind to creative technologists. Investors wanted \`rapid scalability\`, not narrative depth. But Maya had a different vision—what if development tools could be as expressive as they were functional?
> "The best code reads like poetry, and the best software feels like magic." - Maya's personal manifesto
### The Breakthrough Moment
It was during a particularly frustrating debugging session that inspiration struck. As Maya stared at VS Code's interface, she realized something profound:
**Code editors were already storytelling tools—they just didn't know it yet.**
---
*This is the beginning of Maya's journey to revolutionize how creative professionals interact with technology...*
## What's Next?
- [ ] Develop the core editor framework
- [ ] Implement collaborative features
- [ ] Design the preview system
- [ ] Create integration points for creative workflows
**Word Count**: 247 words | **Reading Time**: ~1 minute`;
export default function Home() {
  const [activeView, setActiveView] = useState('explorer');
  const [selectedFile, setSelectedFile] = useState('tab1');
  const [tabs, setTabs] = useState(mockTabs);
  const [activeTab, setActiveTab] = useState('tab1');
  const [editorContent, setEditorContent] = useState(sampleContent);
  const [cursorPosition, setCursorPosition] = useState({ line: 42, column: 15 });
  const [previewFile, setPreviewFile] = useState<any>(null);
  const handleFileSelect = (file: any) => {
    console.log(`Opening file: ${file.name}`);
    setSelectedFile(file.id);
  };
  const handleFileCreate = (parentId: string | null, type: 'file' | 'folder') => {
    console.log(`Creating ${type} in ${parentId || 'root'}`);
  };
  const handleFileRename = (fileId: string, newName: string) => {
    console.log(`Renaming ${fileId} to ${newName}`);
  };
  const handleFileDelete = (fileId: string) => {
    console.log(`Deleting ${fileId}`);
  };
  const handleFilePreview = (file: any) => {
    console.log(`Opening preview for: ${file.name}`);
    setPreviewFile(file);
  };
  const handleTabSelect = (tabId: string) => {
    setActiveTab(tabId);
  };
  const handleTabClose = (tabId: string) => {
    setTabs(prev => prev.filter(tab => tab.id !== tabId));
    if (activeTab === tabId && tabs.length > 1) {
      const remainingTabs = tabs.filter(tab => tab.id !== tabId);
      setActiveTab(remainingTabs[0]?.id || '');
    }
  };
  const handleTabSave = (tabId: string) => {
    setTabs(prev => prev.map(tab => 
      tab.id === tabId ? { ...tab, isDirty: false } : tab
    ));
    console.log('File saved!');
  };
  const handleContentChange = (content: string) => {
    setEditorContent(content);
    // Mark current tab as dirty
    setTabs(prev => prev.map(tab => 
      tab.id === activeTab ? { ...tab, isDirty: true } : tab
    ));
  };
  return (
    <div className="h-screen w-screen bg-background text-foreground flex flex-col overflow-hidden">
      {/* Top Bar */}
      <div className="h-12 bg-sidebar border-b border-sidebar-border flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
          <h1 className="text-lg font-semibold text-sidebar-foreground">NarrativeOS</h1>
          <span className="text-xs text-muted-foreground">Creative Development Environment</span>
        </div>
        <div className="flex items-center gap-2">
          <ThemeToggle />
        </div>
      </div>
      {/* Main Content */}
      <div className="flex-1 flex overflow-hidden">
        {/* Activity Bar */}
        <ActivityBar 
          activeView={activeView}
          onViewChange={setActiveView}
        />
        {/* Main Editor Area */}
        <div className="flex-1 flex flex-col">
          {/* Sidebar + Editor + Preview */}
          <div className="flex-1">
            <ResizablePanes
              defaultSizes={previewFile ? [20, 55, 25] : [20, 80]}
              minSizes={previewFile ? [15, 40, 20] : [15, 60]}
            >
              {/* File Explorer */}
              {activeView === 'explorer' && (
                <FileExplorer
                  files={mockFiles}
                  onFileSelect={handleFileSelect}
                  onFileCreate={handleFileCreate}
                  onFileRename={handleFileRename}
                  onFileDelete={handleFileDelete}
                  onFilePreview={handleFilePreview}
                  selectedFileId={selectedFile}
                />
              )}
              {/* Editor Section */}
              <div className="flex flex-col h-full">
                <EditorTabs
                  tabs={tabs}
                  activeTabId={activeTab}
                  onTabSelect={handleTabSelect}
                  onTabClose={handleTabClose}
                  onTabSave={handleTabSave}
                />
                <div className="flex-1">
                  <CodeEditor
                    content={editorContent}
                    language="markdown"
                    onChange={handleContentChange}
                    onSave={() => handleTabSave(activeTab)}
                    fileName={tabs.find(tab => tab.id === activeTab)?.name || 'untitled'}
                  />
                </div>
              </div>
              {/* Preview Pane - Only show when previewFile is set */}
              {previewFile && (
                <PreviewPane
                  content={editorContent}
                  language="markdown"
                  fileName={previewFile.name}
                />
              )}
            </ResizablePanes>
          </div>
          {/* Status Bar */}
          <StatusBar
            currentFile={tabs.find(tab => tab.id === activeTab)?.name || 'untitled'}
            cursorPosition={cursorPosition}
            language="Markdown"
            encoding="UTF-8"
            lineEnding="LF"
            gitBranch="main"
            errors={0}
            warnings={0}
            isOnline={true}
          />
        </div>
      </div>
    </div>
  );
}import { Card, CardContent } from "@/components/ui/card";
