// --- Application Initialization ---
// NOTE: Rendering and UI initialization have been moved to `index.html`
// to keep this file focused on application logic and components.
// Expose key providers/components to the window so `index.html` can reuse them
if (typeof window !== 'undefined') {
  try {
    window.ThemeProvider = ThemeProvider;
    window.CollapsibleProvider = CollapsibleProvider;
    window.AppProvider = AppProvider;
    // A convenience wrapper that composes the three providers so external mounts
    // (for example the inline mount in `index.html`) can consume a single
    // `Providers` component instead of wiring each provider individually.
    window.Providers = ({ children }) => (
      React.createElement(ThemeProvider, null,
        React.createElement(CollapsibleProvider, null,
          React.createElement(AppProvider, null, children)
        )
      )
    );
    // expose some useful hooks/components if present
    window.useApp = useApp;
    window.useTheme = useTheme;
    window.Icons = Icons;
    window.Button = Button;
    // App component (may be defined later in the file); guard against undefined
    if (typeof App !== 'undefined') window.App = App;
  } catch (e) {
    // noop in environments where assignment fails
    console.warn('Could not attach providers to window', e);
  }
}<!DOCTYPE html>
