  <script>/* small preflight + mock data retained from original (trimmed) */ (function(){ try{const s=localStorage.getItem('theme')||'light';document.documentElement.classList.remove('light','dark');document.documentElement.classList.add(s);}catch(e){} window.mockStories = window.mockStories || [{id:1,title:"The Last Signal",cover:"https://via.placeholder.com/300x200",progress:65,genre:"Sci-Fi",chapters:12,words:25400,lastEdited:"2 hours ago"},{id:2,title:"Echoes of Tomorrow",cover:"https://via.placeholder.com/300x200",progress:30,genre:"Drama",chapters:8,words:15200,lastEdited:"1 day ago"}]; window.mockRecent = window.mockRecent || [{title:"The Last Signal",meta:"Sci-Fi Space • Writing Phase • Edited 11 days ago"},{title:"Urban Legends",meta:"Horror • Storyboard Phase • Edited 11 days ago"},{title:"Memory Lane",meta:"Drama • Editor Phase • Edited 28 days ago"},{title:"Cosmic Journey",meta:"Sci-Fi • Writing Phase • Edited 1 month ago"}]; window.setupDashboardUI = window.setupDashboardUI || function(){ document.querySelectorAll('[data-action="toggleNotifications"]').forEach(el=>el.addEventListener('click',()=>document.getElementById('notificationsModal')?.classList.toggle('hidden'))); document.querySelectorAll('[data-action="toggleTemplates"]').forEach(el=>el.addEventListener('click',()=>document.getElementById('templatesModal')?.classList.toggle('hidden'))); document.querySelectorAll('[data-action="toggleHeaderModal"]').forEach(el=>el.addEventListener('click',()=>document.getElementById('headerModal')?.classList.toggle('hidden'))); document.querySelectorAll('[data-action="markAllAsRead"]').forEach(el=>el.addEventListener('click',()=>{document.querySelectorAll('#notificationsModal .bg-red-500').forEach(d=>d.remove())})); document.querySelectorAll('[data-target]').forEach(el=>el.addEventListener('click',function(e){e.preventDefault(); const t=this.getAttribute('data-target'); const params=new URLSearchParams(); if(t.includes(':')){const [k,v]=t.split(':'); params.set(k,v);} else if(t.includes('=')){const [k,v]=t.split('='); params.set(k,v);} else params.set('q',t); try{const p=document.createElement('link');p.rel='prefetch';p.href='index.html';document.head.appendChild(p);}catch(_){} window.location.href='index.html?'+params.toString(); })); } })();</script>
  <link href="https://cdn.quilljs.com/1.3.6/quill.snow.css" rel="stylesheet" />
  <script src="https://unpkg.com/feather-icons"></script>
  <script src="https://d3js.org/d3.v7.min.js"></script>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/animejs/3.2.1/anime.min.js"></script>
  <script src="https://cdn.jsdelivr.net/npm/sortablejs@latest/Sortable.min.js"></script>
