</html>/* Tailwind CSS Integration for NarratingOS */
@tailwind base;
@tailwind components;
@tailwind utilities;
@layer base {
  :root {
    /* Light theme colors */
    --background: 0 0% 100%;
    --foreground: 240 10% 3.9%;
    --card: 0 0% 100%;
