  <script>
    function toggleNotifications() {
      const modal = document.getElementById('notificationsModal');
      modal.classList.toggle('hidden');
    }
    function toggleTemplates() {
      const modal = document.getElementById('templatesModal');
      modal.classList.toggle('hidden');
    }
    function toggleHeaderModal() {
      const modal = document.getElementById('headerModal');
      modal.classList.toggle('hidden');
    }
    function markAllAsRead() {
      // Remove red dots from all notifications
      const redDots = document.querySelectorAll('#notificationsModal .bg-red-500');
      redDots.forEach(dot => {
        if (dot.classList.contains('w-2')) { // Only remove notification dots, not profile pictures
          dot.remove();
        }
      });
    }
    // Close modals when clicking outside
    document.getElementById('notificationsModal').addEventListener('click', function(e) {
      if (e.target === this) {
        toggleNotifications();
      }
    });
    document.getElementById('templatesModal').addEventListener('click', function(e) {
      if (e.target === this) {
        toggleTemplates();
      }
    });
    document.getElementById('headerModal').addEventListener('click', function(e) {
      if (e.target === this) {
        toggleHeaderModal();
      }
    });
    // Deep-link helper: redirect to proto/index.html with encoded params
    (function setupDeepLinking(){
      function handleTargetClick(el){
        const target = el.getAttribute('data-target');
        if(!target) return;
        // Parse the data-target format: e.g. 'module:storywriter' or 'open:templates' or 'flow:onboard' or 'tab=projects'
        const params = new URLSearchParams();
        if(target.includes('=')){
          // simple tab=projects
          const [k,v] = target.split('=');
          params.set(k, v);
        } else if(target.includes(':')){
          const [k,v] = target.split(':');
          if(k === 'module') params.set('module', v);
          else if(k === 'open') params.set('open', v);
          else if(k === 'flow') params.set('flow', v);
          else params.set(k, v);
        } else {
          params.set('q', target);
        }
        // Prefetch proto/index.html for faster load
        try{
          const p = document.createElement('link');
          p.rel = 'prefetch';
          p.href = 'index.html';
          document.head.appendChild(p);
        }catch(err){/* no-op */}
        // Fire a console telemetry event (placeholder for sendBeacon)
        try{
          console.info('Deep-link click:', target);
        }catch(e){}
        // Navigate same-tab to the prototype with params
        window.location.href = 'index.html?' + params.toString();
      }
      // Attach to all elements with data-target
      document.querySelectorAll('[data-target]').forEach(el => {
        el.addEventListener('click', function(e){
          e.preventDefault();
          handleTargetClick(el);
        });
      });
    })();
  </script>
</body>
