</files>// Import necessary modules from React and ReactDOM (using globals for UMD)
const { createRoot } = ReactDOM;
const { useState, createContext, useContext, useEffect, useCallback, useRef } = React;

// --- Contexts ---
const ThemeContext = createContext();
const AppContext = createContext();

const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState('light');

  // Initialize theme on component mount
  useEffect(() => {
    // Check for saved theme in localStorage or default to light
    const savedTheme = localStorage.getItem('theme') || 'light';
    setTheme(savedTheme);
    document.documentElement.classList.remove('light', 'dark');
    document.documentElement.classList.add(savedTheme);
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.remove('light', 'dark');
    document.documentElement.classList.add(newTheme);
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

// --- Collapsible Island Context ---
const CollapsibleContext = createContext();

const CollapsibleProvider = ({ children }) => {
  const [leftIslandCollapsed, setLeftIslandCollapsed] = useState(false);
  const [rightIslandCollapsed, setRightIslandCollapsed] = useState(false);

  const toggleLeftIsland = () => setLeftIslandCollapsed(!leftIslandCollapsed);
  const toggleRightIsland = () => setRightIslandCollapsed(!rightIslandCollapsed);

  return (
    <CollapsibleContext.Provider value={{
      leftIslandCollapsed,
      rightIslandCollapsed,
      toggleLeftIsland,
      toggleRightIsland
    }}>
      {children}
    </CollapsibleContext.Provider>
  );
};

const useCollapsible = () => useContext(CollapsibleContext);

const AppProvider = ({ children }) => {
  const [currentStory, setCurrentStory] = useState(null);
  const [stories, setStories] = useState(mockStories);
  const [characters, setCharacters] = useState(mockCharacters);
  const [activeSpace, setActiveSpace] = useState('writing');
  const [aiAssistantOpen, setAiAssistantOpen] = useState(true);
  const [showTransition, setShowTransition] = useState(false);

  const updateStory = useCallback((storyId, updates) => {
    setStories(prev => prev.map(story => 
      story.id === storyId ? { ...story, ...updates } : story
    ));
    if (currentStory?.id === storyId) {
      setCurrentStory(prev => ({ ...prev, ...updates }));
    }
  }, [currentStory]);

  const addCharacter = useCallback((character) => {
    const newCharacter = { ...character, id: Date.now() };
    setCharacters(prev => [...prev, newCharacter]);
    return newCharacter;
  }, []);

  const updateCharacter = useCallback((characterId, updates) => {
    setCharacters(prev => prev.map(char => 
      char.id === characterId ? { ...char, ...updates } : char
    ));
  }, []);

  const switchSpace = useCallback((space) => {
    setShowTransition(true);
    setTimeout(() => {
      setActiveSpace(space);
      setShowTransition(false);
    }, 300);
  }, []);

  return (
    <AppContext.Provider value={{
      currentStory, setCurrentStory,
      stories, setStories, updateStory,
      characters, setCharacters, addCharacter, updateCharacter,
      activeSpace, setActiveSpace, switchSpace,
      aiAssistantOpen, setAiAssistantOpen,
      showTransition
    }}>
      {children}
    </AppContext.Provider>
  );
};

const useTheme = () => useContext(ThemeContext);
const useApp = () => useContext(AppContext);

// --- Collapsible Island Component ---
const CollapsibleIsland = ({ 
  children, 
  title, 
  icon: Icon, 
  position = 'left', 
  defaultCollapsed = false,
  className = '',
  collapsedHeight = 60 
}) => {
  const [isCollapsed, setIsCollapsed] = useState(defaultCollapsed);
  const contentRef = useRef(null);

  const toggleCollapsed = () => {
    setIsCollapsed(!isCollapsed);
  };

  const islandStyles = {
    left: 'left-4',
    right: 'right-4'
  };

  return (
    <div 
      className={`
        fixed top-20 ${islandStyles[position]} z-40
        bg-background/95 backdrop-blur-sm border rounded-2xl shadow-2xl
        transition-all duration-500 ease-out
        ${isCollapsed ? 'w-16' : 'w-80'}
        ${className}
      `}
      style={{
        maxHeight: isCollapsed ? `${collapsedHeight}px` : 'calc(100vh - 100px)'
      }}
    >
      {/* Header/Trigger */}
      <div 
        className={`
          flex items-center gap-3 p-4 cursor-pointer
          hover:bg-muted/50 transition-colors duration-200
          ${isCollapsed ? 'rounded-2xl justify-center' : 'rounded-t-2xl border-b'}
        `}
        onClick={toggleCollapsed}
      >
        <div className={`flex items-center gap-3 ${isCollapsed ? '' : 'flex-1'}`}>
          {Icon && (
            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
              <Icon className="w-4 h-4 text-primary" />
            </div>
          )}
          <span className={`font-medium transition-opacity duration-300 ${isCollapsed ? 'opacity-0 w-0 overflow-hidden' : 'opacity-100'}`}>
            {title}
          </span>
        </div>

        <div className={`transform transition-transform duration-300 ${isCollapsed ? 'rotate-0 hidden' : 'rotate-180'}`}>
          <Icons.ChevronUp className="w-4 h-4 text-muted-foreground" />
        </div>
      </div>

      {/* Content */}
      <div 
        ref={contentRef}
        className={`
          overflow-hidden transition-all duration-500 ease-out
          ${isCollapsed ? 'max-h-0 opacity-0' : 'max-h-[calc(100vh-180px)] opacity-100'}
        `}
      >
        <div className="overflow-y-auto max-h-full">
          {children}
        </div>
      </div>
    </div>
  );
};

// --- Enhanced Sidebar as Collapsible Island ---
const SidebarIsland = () => {
  const { stories, currentStory, setCurrentStory, switchSpace } = useApp();
  const { theme, toggleTheme } = useTheme();

  return (
    <CollapsibleIsland
      title="Stories"
      icon={Icons.Book}
      position="left"
      defaultCollapsed={false}
    >
      {/* Stories Content */}
      <div className="p-4 space-y-3">
        {stories.map((story) => {
          const isExpanded = currentStory?.id === story.id;

          return (
            <div key={story.id} className="bg-card border border-border rounded-lg cursor-pointer overflow-hidden transition-all duration-300 hover:shadow-md hover:-translate-y-0.5">
              <div 
                className="p-3"
                onClick={() => setCurrentStory(story)}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-3 flex-1">
                    <div className="bg-primary rounded-lg flex items-center justify-center text-primary-foreground font-bold transition-all duration-300 w-8 h-8 text-sm">
                      {story.title.charAt(0)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <h3 className="font-bold truncate transition-all duration-300 text-base">{story.title}</h3>
                      <p className="text-muted-foreground text-sm truncate">{story.genre}</p>
                    </div>
                  </div>
                  <div className="flex items-center">
                    <button className="p-2 rounded hover:bg-muted cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95">
                      <Icons.ChevronDown className={`w-4 h-4 transition-transform duration-200 ${isExpanded ? '' : 'rotate-180'}`} />
                    </button>
                  </div>
                </div>

                {/* Expanded Details */}
                {isExpanded && (
                  <div className="mt-4 space-y-3 animate-slide-down">
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Progress</span>
                      <span className="font-medium">{story.progress}%</span>
                    </div>
                    <div className="w-full bg-muted rounded-full h-2">
                      <div 
                        className="bg-primary h-2 rounded-full transition-all duration-500" 
                        style={{ width: `${story.progress}%` }}
                      />
                    </div>
                    <div className="flex items-center justify-between text-sm text-muted-foreground">
                      <span>{story.chapters} chapters</span>
                      <span>{story.words.toLocaleString()} words</span>
                    </div>
                    <div className="text-xs text-muted-foreground flex items-center">
                      <Icons.Clock className="w-3 h-3 mr-1" />
                      <span>Last edited {story.lastEdited}</span>
                    </div>
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {/* New Story Button */}
        <button className="inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95 bg-secondary text-secondary-foreground hover:bg-secondary/80 h-10 px-4 py-2 w-full mt-4">
          <Icons.Plus className="w-4 h-4 mr-2" />
          <span>New Story</span>
        </button>
      </div>

      {/* Settings Footer */}
      <div className="border-t p-4 space-y-2">
        <button className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-muted transition-colors">
          <Icons.Settings className="w-4 h-4" />
          <span className="text-sm">Settings</span>
        </button>
      </div>
    </CollapsibleIsland>
  );
};

// --- AI Assistant as Collapsible Island ---
const AIAssistantIsland = () => {
  const [message, setMessage] = useState('');
  const [chatHistory, setChatHistory] = useState([
    {
      id: 1,
      type: 'ai',
      message: "Hello! I'm your AI writing assistant. How can I help you today?",
      timestamp: new Date()
    }
  ]);

  const sendMessage = () => {
    if (!message.trim()) return;

    const userMessage = {
      id: Date.now(),
      type: 'user',
      message: message,
      timestamp: new Date()
    };

    setChatHistory(prev => [...prev, userMessage]);
    setMessage('');

    // Simulate AI response
    setTimeout(() => {
      const aiMessage = {
        id: Date.now() + 1,
        type: 'ai',
        message: "I understand you'd like help with that. Let me provide some suggestions...",
        timestamp: new Date()
      };
      setChatHistory(prev => [...prev, aiMessage]);
    }, 1000);
  };

  return (
    <CollapsibleIsland
      title="AI Assistant"
      icon={Icons.Bot}
      position="right"
      defaultCollapsed={false}
    >
      {/* Chat History */}
      <div className="h-80 overflow-y-auto p-4 space-y-4">
        {chatHistory.map((chat) => (
          <div key={chat.id} className={`flex ${chat.type === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-lg ${
              chat.type === 'user' 
                ? 'bg-primary text-primary-foreground' 
                : 'bg-muted text-foreground'
            }`}>
              <p className="text-sm">{chat.message}</p>
              <div className="text-xs opacity-70 mt-1">
                {chat.timestamp.toLocaleTimeString()}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Input */}
      <div className="border-t p-4">
        <div className="flex space-x-2">
          <input
            type="text"
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
            placeholder="Ask me anything..."
            className="flex-1 px-3 py-2 border rounded-lg bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
          />
          <button 
            onClick={sendMessage}
            className="px-3 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <Icons.Send className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="border-t p-4">
        <div className="grid grid-cols-2 gap-2 text-xs">
          <button className="p-2 border rounded-lg hover:bg-muted transition-colors">
            <Icons.Lightbulb className="w-3 h-3 mx-auto mb-1" />
            <div>Plot Ideas</div>
          </button>
          <button className="p-2 border rounded-lg hover:bg-muted transition-colors">
            <Icons.Users className="w-3 h-3 mx-auto mb-1" />
            <div>Characters</div>
          </button>
          <button className="p-2 border rounded-lg hover:bg-muted transition-colors">
            <Icons.BookOpen className="w-3 h-3 mx-auto mb-1" />
            <div>Grammar</div>
          </button>
          <button className="p-2 border rounded-lg hover:bg-muted transition-colors">
            <Icons.Zap className="w-3 h-3 mx-auto mb-1" />
            <div>Enhance</div>
          </button>
        </div>
      </div>
    </CollapsibleIsland>
  );
};

