      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {characters.map((character) => (
          <div
            key={character.id}
            className={`character-card card cursor-pointer border-2 transition-all duration-300 ${
              selectedCharacter?.id === character.id ? 'border-primary bg-primary/5' : 'border-transparent'
            }`}
            onClick={() => setSelectedCharacter(selectedCharacter?.id === character.id ? null : character)}
          >
            <div className="flex items-start space-x-3">
              <div className="w-12 h-12 bg-primary rounded-full flex items-center justify-center text-primary-foreground font-semibold">
                {character.name.split(' ').map(n => n[0]).join('')}
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <h4 className="font-medium">{character.name}</h4>
                  <span className="text-xs bg-secondary px-2 py-1 rounded">{character.role}</span>
                </div>
                <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                  {character.description}
                </p>
                <div className="flex items-center mt-2 space-x-2">
                  <span className="text-xs bg-accent px-2 py-1 rounded">{character.arc} Arc</span>
                  <span className="text-xs text-muted-foreground">
                    {character.relationships.length} relationships
                  </span>
                </div>
              </div>
            </div>

            {/* Expanded character details */}
            {selectedCharacter?.id === character.id && (
              <div className="mt-4 pt-4 border-t animate-fade-in">
                <div className="space-y-3">
                  <div>
                    <h5 className="text-sm font-medium mb-1">Relationships</h5>
                    <div className="flex flex-wrap gap-1">
                      {character.relationships.map(rel => (
                        <span key={rel} className="text-xs bg-muted px-2 py-1 rounded">
                          {rel}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="flex space-x-2">
                    <Button variant="outline" size="sm" className="flex-1">
                      <Icons.Edit />
                      <span className="ml-1">Edit</span>
                    </Button>
                    <Button variant="outline" size="sm" className="flex-1">
                      <Icons.FileText />
                      <span className="ml-1">Profile</span>
                    </Button>
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Add Character Modal */}
      {showAddCharacter && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-fade-in">
          <div className="bg-card p-6 rounded-lg border max-w-md w-full mx-4 animate-scale-in">
            <div className="flex items-center justify-between mb-4">
              <h4 className="font-medium">Add New Character</h4>
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setShowAddCharacter(false)}
              >
                <Icons.X />
              </Button>
            </div>
            <div className="space-y-4">
              <input 
                type="text" 
                placeholder="Character name"
                className="w-full p-2 border rounded"
              />
              <textarea 
                placeholder="Character description"
                className="w-full p-2 border rounded h-20 resize-none"
              />
              <select className="w-full p-2 border rounded">
                <option>Select role...</option>
                <option>Protagonist</option>
                <option>Deuteragonist</option>
                <option>Antagonist</option>
                <option>Supporting</option>
              </select>
              <div className="flex space-x-2">
                <Button 
                  className="flex-1"
                  onClick={() => setShowAddCharacter(false)}
                >
                  Add Character
                </Button>
                <Button 
                  variant="outline" 
                  className="flex-1"
                  onClick={() => setShowAddCharacter(false)}
                >
                  Cancel
                </Button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Enhanced AI Assistant Component with Categorized Suggestions
const AIAssistant = () => {
  const { aiAssistantOpen, setAiAssistantOpen } = useApp();
  const [selectedSuggestion, setSelectedSuggestion] = useState(null);
  const [activeCategory, setActiveCategory] = useState('all');
  const [isTyping, setIsTyping] = useState(false);

  const categories = [
    { id: 'all', label: 'All', icon: 'Grid' },
    { id: 'Character Development', label: 'Characters', icon: 'Users' },
    { id: 'Plot Development', label: 'Plot', icon: 'BookOpen' },
    { id: 'World Building', label: 'World', icon: 'Globe' },
    { id: 'Dialogue', label: 'Dialogue', icon: 'MessageCircle' }
  ];

  const filteredSuggestions = activeCategory === 'all' 
    ? mockAISuggestions 
    : mockAISuggestions.filter(s => s.category === activeCategory);

  const handleSuggestionClick = (suggestion) => {
    setSelectedSuggestion(suggestion);
    setIsTyping(true);
    setTimeout(() => setIsTyping(false), 2000);
  };

  if (!aiAssistantOpen) {
    return (
      <button 
        className="fixed right-4 top-20 w-12 h-12 bg-primary text-primary-foreground rounded-full flex items-center justify-center cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95 animate-bounce"
        onClick={() => setAiAssistantOpen(true)}
      >
        <Icons.Zap />
      </button>
    );
  }

  return (
    <div className="w-80 border-l bg-muted/30 flex flex-col animate-slide-left">
      <div className="p-4 border-b">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold flex items-center">
            <Icons.Zap />
            <span className="ml-2">AI Writing Assistant</span>
          </h3>
          <Button 
            variant="ghost" 
            size="sm"
            onClick={() => setAiAssistantOpen(false)}
            className=""
          >
            <Icons.X />
          </Button>
        </div>
        <p className="text-sm text-muted-foreground mt-1">
          Contextual questions and creative prompts
        </p>
      </div>

      {/* Category Filters */}
      <div className="p-4 border-b">
        <div className="grid grid-cols-3 gap-2">
          {categories.map(category => (
            <button
              key={category.id}
              onClick={() => setActiveCategory(category.id)}
              className={`p-2 rounded text-xs font-medium transition-all duration-200 ${
                activeCategory === category.id 
                  ? 'bg-primary text-primary-foreground' 
                  : 'bg-muted hover:bg-muted-foreground/10'
              }`}
