// Enhanced Storyboard Space Component
const StoryboardSpace = () => {
  const { characters } = useApp();
  const [scenes, setScenes] = useState(mockScenes);
  const [selectedScene, setSelectedScene] = useState(null);
  const [draggedScene, setDraggedScene] = useState(null);

  const handleSceneDragStart = (scene) => {
    setDraggedScene(scene);
  };

  const handleSceneDrop = (targetIndex) => {
    if (draggedScene) {
      const newScenes = [...scenes];
      const draggedIndex = newScenes.findIndex(s => s.id === draggedScene.id);
      const [removed] = newScenes.splice(draggedIndex, 1);
      newScenes.splice(targetIndex, 0, removed);
      setScenes(newScenes);
      setDraggedScene(null);
    }
  };

  const getMoodColor = (mood) => {
    const colors = {
      mysterious: '#6366f1',
      tense: '#ef4444',
      hopeful: '#10b981',
      dark: '#374151',
      exciting: '#f59e0b'
    };
    return colors[mood] || '#64748b';
  };

  return (
    <div className="flex-1 p-6 space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Storyboard Space</h2>
          <p className="text-muted-foreground">Visualize and plan your scenes</p>
        </div>
        <Button className="">
          <Icons.Plus />
          <span className="ml-2">Add Scene</span>
        </Button>
      </div>

      {/* Scene Gallery */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {scenes.map((scene, index) => (
          <div
            key={scene.id}
            className={`storyboard-scene bg-card p-4 rounded-lg border cursor-pointer ${
              selectedScene?.id === scene.id ? 'border-primary' : ''
            } ${draggedScene?.id === scene.id ? 'dragging' : ''}`}
            draggable
            onDragStart={() => handleSceneDragStart(scene)}
            onDragOver={(e) => e.preventDefault()}
            onDrop={() => handleSceneDrop(index)}
            onClick={() => setSelectedScene(scene)}
          >
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center space-x-2">
                <div 
                  className="w-3 h-3 rounded-full"
                  style={{ backgroundColor: getMoodColor(scene.mood) }}
                />
                <span className="text-sm font-medium capitalize">{scene.status}</span>
              </div>
              <span className="text-xs text-muted-foreground">{scene.duration}</span>
            </div>

            <h3 className="font-bold mb-2">{scene.title}</h3>
            <p className="text-sm text-muted-foreground mb-3">{scene.description}</p>

            <div className="space-y-2">
              <div className="text-xs text-muted-foreground flex items-center">
                <Icons.MapPin />
                <span className="ml-1">{scene.location}</span>
              </div>
              <div className="flex flex-wrap gap-1">
                {scene.characters.map(charName => (
                  <span 
                    key={charName}
                    className="px-2 py-1 bg-muted rounded text-xs"
                  >
                    {charName.split(' ')[0]}
                  </span>
                ))}
              </div>
            </div>
          </div>
        ))}

        {/* Add Scene Placeholder */}
        <div className="drop-zone active">
          <div className="text-center">
            <Icons.Plus />
            <p className="mt-2">Drop scene here or click to add</p>
          </div>
        </div>
      </div>

      {/* Scene Detail Panel */}
      {selectedScene && (
        <div className="bg-card p-6 rounded-lg border animate-slide-up">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-xl font-bold">{selectedScene.title}</h3>
            <Button 
              variant="ghost"
              className=""
              onClick={() => setSelectedScene(null)}
            >
              <Icons.X />
            </Button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <h4 className="font-medium mb-2">Scene Details</h4>
              <div className="space-y-2 text-sm">
                <div><strong>Duration:</strong> {selectedScene.duration}</div>
                <div><strong>Location:</strong> {selectedScene.location}</div>
                <div><strong>Mood:</strong> {selectedScene.mood}</div>
                <div><strong>Status:</strong> {selectedScene.status}</div>
              </div>
            </div>

            <div>
              <h4 className="font-medium mb-2">Characters</h4>
              <div className="space-y-2">
                {selectedScene.characters.map(charName => {
                  const character = characters.find(c => c.name === charName);
                  return (
                    <div key={charName} className="flex items-center space-x-2">
                      <div className="w-8 h-8 bg-primary rounded-full flex items-center justify-center text-primary-foreground text-xs">
                        {character ? character.name.split(' ').map(n => n[0]).join('') : charName[0]}
                      </div>
                      <span className="text-sm">{charName}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Enhanced Editor Space Component with Timeline
const EditorSpace = () => {
  const [timelineClips, setTimelineClips] = useState(mockTimelineClips);
  const [selectedClip, setSelectedClip] = useState(null);
  const [playheadPosition, setPlayheadPosition] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTrackLabel = (track) => {
    const labels = {
      0: 'Video Track',
      1: 'Audio Track',
      2: 'Music Track',
      3: 'SFX Track'
    };
    return labels[track] || `Track ${track + 1}`;
  };

  const totalDuration = Math.max(...timelineClips.map(clip => clip.start + clip.duration));

  return (
    <div className="flex-1 p-6 space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Editor Space</h2>
          <p className="text-muted-foreground">Timeline editing and post-production planning</p>
        </div>
        <div className="flex items-center space-x-2">
          <Button 
            variant={isPlaying ? "default" : "outline"}
            className=""
            onClick={() => setIsPlaying(!isPlaying)}
          >
            {isPlaying ? <Icons.Pause /> : <Icons.Play />}
            <span className="ml-2">{isPlaying ? 'Pause' : 'Play'}</span>
          </Button>
          <Button className="">
            <Icons.Download />
            <span className="ml-2">Export</span>
          </Button>
        </div>
      </div>

      {/* Timeline Controls */}
      <div className="bg-card p-4 rounded-lg border">
        <div className="flex items-center justify-between mb-4">
          <div className="text-sm">
            <span className="font-medium">Playhead: </span>
            <span className="text-muted-foreground">{formatTime(playheadPosition)}</span>
            <span className="mx-2">•</span>
            <span className="font-medium">Duration: </span>
            <span className="text-muted-foreground">{formatTime(totalDuration)}</span>
          </div>
          <div className="flex items-center space-x-2">
            <Button variant="ghost" size="sm" className="">
              <Icons.SkipBack />
            </Button>
            <Button variant="ghost" size="sm" className="">
              <Icons.Rewind />
            </Button>
            <Button variant="ghost" size="sm" className="">
              <Icons.FastForward />
            </Button>
            <Button variant="ghost" size="sm" className="">
              <Icons.SkipForward />
            </Button>
          </div>
        </div>

        {/* Timeline Ruler */}
        <div className="relative mb-2">
          <div className="h-8 border-b border-border flex items-end">
            {Array.from({ length: Math.ceil(totalDuration / 60) + 1 }, (_, i) => (
              <div key={i} className="flex-none" style={{ width: '60px' }}>
                <div className="text-xs text-muted-foreground">{i}:00</div>
                <div className="w-px h-2 bg-border"></div>
              </div>
            ))}
          </div>
          {/* Playhead */}
          <div 
            className="absolute top-0 w-0.5 h-full bg-red-500 pointer-events-none"
            style={{ left: `${(playheadPosition / totalDuration) * 100}%` }}
          />
        </div>
      </div>

      {/* Timeline Tracks */}
      <div className="bg-card rounded-lg border overflow-hidden">
        <div className="border-b bg-muted/50 p-3">
          <h3 className="font-medium">Timeline</h3>
        </div>

        <div className="space-y-1 p-3">
          {[0, 1, 2, 3].map(trackIndex => {
            const trackClips = timelineClips.filter(clip => clip.track === trackIndex);

            return (
              <div key={trackIndex} className="relative">
                <div className="flex items-center mb-1">
                  <div className="w-24 text-sm font-medium">
                    {getTrackLabel(trackIndex)}
                  </div>
                  <Button variant="ghost" size="sm" className="ml-auto">
                    <Icons.Settings />
                  </Button>
                </div>

                <div className="timeline-track relative" style={{ width: `${Math.max(800, totalDuration)}px` }}>
                  {trackClips.map(clip => (
                    <div
                      key={clip.id}
                      className={`timeline-clip ${selectedClip?.id === clip.id ? 'selected' : ''}`}
                      style={{
                        left: `${clip.start}px`,
                        width: `${clip.duration}px`,
                        backgroundColor: clip.color
                      }}
                      onClick={() => setSelectedClip(clip)}
                    >
                      <div className="p-2 text-xs text-white truncate">
                        Scene {clip.sceneId}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Clip Properties Panel */}
      {selectedClip && (
        <div className="bg-card p-6 rounded-lg border animate-slide-up">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-bold">Clip Properties</h3>
            <Button 
              variant="ghost"
              className=""
              onClick={() => setSelectedClip(null)}
            >
              <Icons.X />
            </Button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <h4 className="font-medium mb-2">Basic Properties</h4>
              <div className="space-y-2 text-sm">
                <div><strong>Type:</strong> {selectedClip.type}</div>
                <div><strong>Start:</strong> {formatTime(selectedClip.start)}</div>
                <div><strong>Duration:</strong> {formatTime(selectedClip.duration)}</div>
                <div><strong>Track:</strong> {getTrackLabel(selectedClip.track)}</div>
              </div>
            </div>

            <div>
              <h4 className="font-medium mb-2">Effects</h4>
              <div className="space-y-2">
                <Button variant="outline" size="sm" className="w-full">
                  <Icons.Zap />
                  <span className="ml-2">Add Transition</span>
                </Button>
                <Button variant="outline" size="sm" className="w-full">
                  <Icons.Star />
                  <span className="ml-2">Color Correction</span>
                </Button>
                <Button variant="outline" size="sm" className="w-full">
                  <Icons.Volume2 />
                  <span className="ml-2">Audio Effects</span>
                </Button>
              </div>
            </div>

            <div>
              <h4 className="font-medium mb-2">Notes</h4>
              <textarea 
                className="w-full h-20 p-2 text-sm border border-border rounded resize-none"
                placeholder="Add production notes..."
              />
            </div>
          </div>
        </div>
      )}

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="p-4 text-center card-hover cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95">
          <Icons.Film />
          <h3 className="font-medium mt-2 mb-1">Shot List</h3>
          <p className="text-sm text-muted-foreground">Manage individual shots</p>
        </Card>
        <Card className="p-4 text-center card-hover cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95">
          <Icons.Music />
          <h3 className="font-medium mt-2 mb-1">Audio Sync</h3>
          <p className="text-sm text-muted-foreground">Sync audio to video</p>
        </Card>
        <Card className="p-4 text-center card-hover cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95">
          <Icons.Palette />
          <h3 className="font-medium mt-2 mb-1">Color Grading</h3>
          <p className="text-sm text-muted-foreground">Apply color corrections</p>
        </Card>
      </div>
    </div>
  );
};

// Enhanced Main App Component with Collapsible Islands
const App = () => {
  const { activeSpace, showTransition } = useApp();
