// SpaceButton Component
const SpaceButton = ({ icon: Icon, label, active, space, onClick, className = '' }) => {
  const { navigate } = window.useRouter();

  const handleClick = () => {
    if (onClick) {
      onClick();
    } else {
      const routePath = `/${space.toLowerCase()}`;
      navigate(routePath);
    }
  };

  return (
    <button
      onClick={handleClick}
      className={cn(
        'inline-flex items-center space-x-2 px-3 py-2 rounded-md text-sm font-medium transition-all duration-150 ease-in-out cursor-pointer border-0 bg-transparent text-foreground no-underline hover:bg-accent hover:text-accent-foreground',
        active ? 'bg-primary text-primary-foreground' : '',
        className
      )}
    >
      <Icon className="w-4 h-4" />
      <span>{label}</span>
    </button>
  );
};

