// --- TabBar Component (top-level tabs) ---
const TabBar = () => {
  const { navigate } = window.useRouter();
  const [activeTab, setActiveTab] = useState('Projects');

  const tabs = [
    { id: 'Dashboard', label: 'Dashboard' },
    { id: 'Projects', label: 'Projects' },
    { id: 'Story', label: 'Story' },
    { id: 'Script', label: 'Script' },
    { id: 'Templates', label: 'Templates' }
  ];

  const onTabClick = (tabId) => {
    setActiveTab(tabId);
    if (tabId === 'Templates') {
      // dispatch a custom event the AppProvider can pick up via context or global
      const ev = new CustomEvent('proto:openTemplates');
      window.dispatchEvent(ev);
    }

    // Navigate to Writing space for all tabs (proto behavior)
    navigate('/writing');

    // push query param for sharable proto links
    try {
      const url = new URL(window.location.href);
      url.searchParams.set('tab', tabId.toLowerCase());
      window.history.pushState({}, '', url.pathname + '?' + url.searchParams.toString());
    } catch (e) {
      // fallback
      window.location.hash = `#${tabId.toLowerCase()}`;
    }
  };

  return (
    <div className="w-full border-b bg-background/80">
      <div className="max-w-7xl mx-auto px-4">
        <div className="flex space-x-2 py-2">
          {tabs.map(t => (
            <button
              key={t.id}
              onClick={() => onTabClick(t.id)}
              className={cn('px-3 py-2 rounded-md text-sm font-medium', activeTab === t.id ? 'bg-primary text-primary-foreground' : 'hover:bg-accent')}
            >
              {t.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

