// route.js

// NarratingOS Routing System
const { createContext, useContext, useState, useCallback, useEffect } = React;

// Define routes configuration with existing and future modules
const routes = [
  // Current active spaces
  {
    path: '/writing',
    name: 'Writing',
    icon: 'edit-3',
    shortcut: '⌘1',
