  return (
    &lt;div className=&quot;flex items-center&quot;&gt;
      &lt;button
        onClick={(e) =&gt; handleClick(e, &apos;assistant&apos;)}
        aria-pressed={activeTab === &apos;assistant&apos;}
        aria-label=&quot;AI tab&quot;
        className={`text-md px-2 py-1 rounded-md transition-colors duration-150 mr-2 ${activeTab === &apos;assistant&apos; ? &apos;bg-primary text-primary-foreground&apos; : &apos;bg-transparent text-muted-foreground&apos;}`}
      &gt;
        AI
      &lt;/button&gt;
      &lt;button
        onClick={(e) =&gt; handleClick(e, &apos;world&apos;)}
        aria-pressed={activeTab === &apos;world&apos;}
        aria-label=&quot;World tab&quot;
        className={`text-md px-2 py-1 rounded-md transition-colors duration-150 ${activeTab === &apos;world&apos; ? &apos;bg-primary text-primary-foreground&apos; : &apos;bg-transparent text-muted-foreground&apos;}`}
      &gt;
        World
      &lt;/button&gt;
    &lt;/div&gt;
  );
};
const CollapsibleIsland = ({
  children,
  title,
  icon: Icon,
  position = &apos;left&apos;,
  defaultCollapsed = false,
  className = &apos;&apos;,
  collapsedHeight = 60,
  headerControls = null
  , showHeaderLabel = true, showIcon = true
}) =&gt; {
  const [isCollapsed, setIsCollapsed] = useState(defaultCollapsed);
  const contentRef = useRef(null);
  const toggleCollapsed = () =&gt; {
    setIsCollapsed(!isCollapsed);
  };
  const islandStyles = {
    left: &apos;left-4&apos;,
    right: &apos;right-4&apos;
  };
  // when headerControls are present, give collapsed island extra width so controls fit
  // make pill wider when header controls (tabs) are present (e.g., AI assistant needs space for two tabs)
  const collapsedWidthClass = headerControls ? &apos;w-52&apos; : &apos;w-12&apos;;
  // If headerControls is a React element, inject an openIsland handler so header buttons can expand the island
  let injectedHeaderControls = headerControls;
  try {
    if (headerControls &amp;&amp; typeof headerControls === &apos;object&apos; &amp;&amp; React.isValidElement(headerControls)) {
      injectedHeaderControls = React.cloneElement(headerControls, { openIsland: () =&gt; setIsCollapsed(false), isCollapsed });
    }
  } catch (e) {
    // fallback - leave headerControls as-is
  }
  return (
    &lt;div
      className={`
        fixed top-20 ${islandStyles[position]} z-40
        bg-background/95 backdrop-blur-sm border rounded-2xl shadow-2xl
        transition-all duration-500 ease-out
  ${isCollapsed ? collapsedWidthClass : position === &apos;right&apos; ? &apos;w-96&apos; : &apos;w-80&apos;}
        ${className}
      `}
      style={{
        maxHeight: isCollapsed ? `${collapsedHeight}px` : &apos;calc(100vh - 100px)&apos;
      }}
    &gt;
      {/* Header/Trigger */}
      &lt;div
        className={`
          flex items-center gap-3 p-4 cursor-pointer
          hover:bg-muted/50 transition-colors duration-200
          ${isCollapsed ? &apos;rounded-full justify-center h-12 px-3&apos; : &apos;rounded-t-2xl border-b&apos;}
        `}
        onClick={toggleCollapsed}
      &gt;
        {/* Use new HeaderIconLabel helper so icon/label visibility can be toggled easily */}
        &lt;HeaderIconLabel Icon={Icon} title={title} showIcon={showIcon} showLabel={showHeaderLabel} isCollapsed={isCollapsed} /&gt;
        {/* header controls (tabs, actions) - always visible (even when collapsed). The controls themselves stop propagation when clicked. */}
        {injectedHeaderControls &amp;&amp; (
          &lt;div className={`ml-2`} onClick={(e) =&gt; e.stopPropagation()}&gt;
            {injectedHeaderControls}
          &lt;/div&gt;
        )}
        &lt;div className={`transform transition-transform duration-300 ${isCollapsed ? &apos;rotate-0 hidden&apos; : &apos;rotate-180&apos;}`}&gt;
          &lt;Icons.ChevronUp className=&quot;w-4 h-4 text-muted-foreground&quot; /&gt;
        &lt;/div&gt;
      &lt;/div&gt;
      {/* Content */}
      &lt;div
        ref={contentRef}
        className={`
          overflow-hidden transition-all duration-500 ease-out
          ${isCollapsed ? &apos;max-h-0 opacity-0&apos; : &apos;max-h-[calc(100vh-180px)] opacity-100&apos;}
        `}
      &gt;
        &lt;div className=&quot;overflow-y-auto max-h-full&quot;&gt;
          {children}
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
// --- AI Assistant as Collapsible Island ---
const AIAssistantIsland = () =&gt; {
  const [message, setMessage] = useState(&apos;&apos;);
  const [chatHistory, setChatHistory] = useState([
    {
      id: 1,
      type: &apos;ai&apos;,
      message: &quot;Hello! I&apos;m your AI writing assistant. How can I help you today?&quot;,
      timestamp: new Date()
    }
  ]);
  const sendMessage = () =&gt; {
    if (!message.trim()) return;
    const userMessage = {
      id: Date.now(),
      type: &apos;user&apos;,
      message: message,
      timestamp: new Date()
    };
    setChatHistory(prev =&gt; [...prev, userMessage]);
    setMessage(&apos;&apos;);
    // Simulate AI response
    setTimeout(() =&gt; {
      const aiMessage = {
        id: Date.now() + 1,
        type: &apos;ai&apos;,
        message: &quot;I understand you&apos;d like help with that. Let me provide some suggestions...&quot;,
        timestamp: new Date()
      };
      setChatHistory(prev =&gt; [...prev, aiMessage]);
    }, 1000);
  };
  const [activeTab, setActiveTab] = useState(&apos;assistant&apos;); // &apos;assistant&apos; | &apos;world&apos;
  // headerControls rendered as a HeaderTabs element so CollapsibleIsland can inject openIsland
  const headerTabs = (
    &lt;HeaderTabs activeTab={activeTab} setActiveTab={setActiveTab} isCollapsed={false} /&gt;
  );
  return (
    &lt;CollapsibleIsland
      title=&quot;Assistant&quot;
      // icon={Icons.Bot}
      position=&quot;right&quot;
      defaultCollapsed={false}
      className=&quot;&quot;
      headerControls={headerTabs}
      showHeaderLabel={false} // when collapsed, we want a pill showing only icon+tabs
    &gt;
      {/* Tab panels */}
      {activeTab === &apos;assistant&apos; ? (
        &lt;&gt;
          &lt;div className=&quot;border-t p-4&quot;&gt;
            &lt;div className=&quot;grid grid-cols-2 gap-2 text-xs&quot;&gt;
              &lt;button className=&quot;inline-flex flex-row items-center justify-around px-3 py-2 border rounded-full hover:bg-muted transition-colors text-center&quot;&gt;
                &lt;div className=&quot;whitespace-nowrap&quot;&gt;Plot Ideas&lt;/div&gt;
              &lt;/button&gt;
              &lt;button className=&quot;inline-flex flex-row items-center justify-around px-3 py-2 border rounded-full hover:bg-muted transition-colors text-center&quot;&gt;
                &lt;div className=&quot;whitespace-nowrap&quot;&gt;Characters&lt;/div&gt;
              &lt;/button&gt;
              &lt;button className=&quot;inline-flex flex-row items-center justify-around px-3 py-2 border rounded-full hover:bg-muted transition-colors text-center&quot;&gt;
                &lt;div className=&quot;whitespace-nowrap&quot;&gt;Grammar&lt;/div&gt;
              &lt;/button&gt;
              &lt;button className=&quot;inline-flex flex-row items-center justify-around px-3 py-2 border rounded-full hover:bg-muted transition-colors text-center&quot;&gt;
                &lt;div className=&quot;whitespace-nowrap&quot;&gt;Enhance&lt;/div&gt;
              &lt;/button&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;div className=&quot;h-72 overflow-y-scroll p-4 space-y-4&quot;&gt;
            {chatHistory.map((chat) =&gt; (
              &lt;div key={chat.id} className={`flex ${chat.type === &apos;user&apos; ? &apos;justify-end&apos; : &apos;justify-start&apos;}`}&gt;
                &lt;div className={`max-w-[85%] p-3 rounded-lg ${chat.type === &apos;user&apos;
                    ? &apos;bg-primary text-primary-foreground&apos;
                    : &apos;bg-muted text-foreground&apos;
                  }`}&gt;
                  &lt;p className=&quot;text-sm&quot;&gt;{chat.message}&lt;/p&gt;
                  &lt;div className=&quot;text-xs opacity-70 mt-1&quot;&gt;
                    {chat.timestamp.toLocaleTimeString()}
                  &lt;/div&gt;
                &lt;/div&gt;
              &lt;/div&gt;
            ))}
          &lt;/div&gt;
          &lt;div className=&quot;border-t p-4&quot;&gt;
            &lt;div className=&quot;flex space-x-2&quot;&gt;
              &lt;input
                type=&quot;text&quot;
                value={message}
                onChange={(e) =&gt; setMessage(e.target.value)}
                onKeyPress={(e) =&gt; e.key === &apos;Enter&apos; &amp;&amp; sendMessage()}
                placeholder=&quot;Ask me anything...&quot;
                className=&quot;flex-1 px-3 py-2 border rounded-lg bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring&quot;
              /&gt;
              &lt;button
                onClick={sendMessage}
                className=&quot;px-3 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors&quot;
              &gt;
                &lt;Icons.Send className=&quot;w-4 h-4&quot; /&gt;
              &lt;/button&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        &lt;/&gt;
      ) : (
        // World Building panel
        &lt;div className=&quot;p-4 space-y-3&quot;&gt;
          &lt;h4 className=&quot;font-medium&quot;&gt;World Building Tools&lt;/h4&gt;
          &lt;p className=&quot;text-sm text-muted-foreground&quot;&gt;Quick references and prompts for world details.&lt;/p&gt;
          &lt;div className=&quot;grid grid-cols-1 gap-2&quot;&gt;
            {mockScenes.map(scene =&gt; (
              &lt;div key={scene.id} className=&quot;p-2 border rounded-lg bg-card&quot;&gt;
                &lt;div className=&quot;flex items-center justify-between&quot;&gt;
                  &lt;div&gt;
                    &lt;div className=&quot;font-medium&quot;&gt;{scene.title}&lt;/div&gt;
                    &lt;div className=&quot;text-xs text-muted-foreground&quot;&gt;{scene.location} • {scene.duration}&lt;/div&gt;
                  &lt;/div&gt;
                  &lt;div className=&quot;text-xs bg-secondary px-2 py-1 rounded&quot;&gt;{scene.status}&lt;/div&gt;
                &lt;/div&gt;
                &lt;p className=&quot;text-sm text-muted-foreground mt-2 line-clamp-2&quot;&gt;{scene.description}&lt;/p&gt;
              &lt;/div&gt;
            ))}
          &lt;/div&gt;
          &lt;div className=&quot;pt-2&quot;&gt;
            &lt;Button variant=&quot;outline&quot; className=&quot;w-full&quot;&gt;Open World Builder&lt;/Button&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      )}
    &lt;/CollapsibleIsland&gt;
  );
};
