&lt;/files&gt;</file><file path="NARATING_OS/UI reference/V1.txt">// Import necessary modules from React and ReactDOM (using globals for UMD)
const { createRoot } = ReactDOM;
const { useState, createContext, useContext, useEffect, useCallback, useRef } = React;
// --- Contexts ---
const ThemeContext = createContext();
const AppContext = createContext();
const ThemeProvider = ({ children }) =&gt; {
  const [theme, setTheme] = useState(&apos;light&apos;);
  // Initialize theme on component mount
  useEffect(() =&gt; {
    // Check for saved theme in localStorage or default to light
    const savedTheme = localStorage.getItem(&apos;theme&apos;) || &apos;light&apos;;
    setTheme(savedTheme);
    document.documentElement.classList.remove(&apos;light&apos;, &apos;dark&apos;);
    document.documentElement.classList.add(savedTheme);
  }, []);
  const toggleTheme = () =&gt; {
    const newTheme = theme === &apos;light&apos; ? &apos;dark&apos; : &apos;light&apos;;
    setTheme(newTheme);
    localStorage.setItem(&apos;theme&apos;, newTheme);
    document.documentElement.classList.remove(&apos;light&apos;, &apos;dark&apos;);
    document.documentElement.classList.add(newTheme);
  };
  return (
    &lt;ThemeContext.Provider value={{ theme, toggleTheme }}&gt;
      {children}
    &lt;/ThemeContext.Provider&gt;
  );
};
// --- Collapsible Island Context ---
const CollapsibleContext = createContext();
const CollapsibleProvider = ({ children }) =&gt; {
  const [leftIslandCollapsed, setLeftIslandCollapsed] = useState(false);
  const [rightIslandCollapsed, setRightIslandCollapsed] = useState(false);
  const toggleLeftIsland = () =&gt; setLeftIslandCollapsed(!leftIslandCollapsed);
  const toggleRightIsland = () =&gt; setRightIslandCollapsed(!rightIslandCollapsed);
  return (
    &lt;CollapsibleContext.Provider value={{
      leftIslandCollapsed,
      rightIslandCollapsed,
      toggleLeftIsland,
      toggleRightIsland
    }}&gt;
      {children}
    &lt;/CollapsibleContext.Provider&gt;
  );
};
const useCollapsible = () =&gt; useContext(CollapsibleContext);
const AppProvider = ({ children }) =&gt; {
  const [currentStory, setCurrentStory] = useState(null);
  const [stories, setStories] = useState(mockStories);
  const [characters, setCharacters] = useState(mockCharacters);
  const [activeSpace, setActiveSpace] = useState(&apos;writing&apos;);
  const [aiAssistantOpen, setAiAssistantOpen] = useState(true);
  const [showTransition, setShowTransition] = useState(false);
  const updateStory = useCallback((storyId, updates) =&gt; {
    setStories(prev =&gt; prev.map(story =&gt; 
      story.id === storyId ? { ...story, ...updates } : story
    ));
    if (currentStory?.id === storyId) {
      setCurrentStory(prev =&gt; ({ ...prev, ...updates }));
    }
  }, [currentStory]);
  const addCharacter = useCallback((character) =&gt; {
    const newCharacter = { ...character, id: Date.now() };
    setCharacters(prev =&gt; [...prev, newCharacter]);
    return newCharacter;
  }, []);
  const updateCharacter = useCallback((characterId, updates) =&gt; {
    setCharacters(prev =&gt; prev.map(char =&gt; 
      char.id === characterId ? { ...char, ...updates } : char
    ));
  }, []);
  const switchSpace = useCallback((space) =&gt; {
    setShowTransition(true);
    setTimeout(() =&gt; {
      setActiveSpace(space);
      setShowTransition(false);
    }, 300);
  }, []);
  return (
    &lt;AppContext.Provider value={{
      currentStory, setCurrentStory,
      stories, setStories, updateStory,
      characters, setCharacters, addCharacter, updateCharacter,
      activeSpace, setActiveSpace, switchSpace,
      aiAssistantOpen, setAiAssistantOpen,
      showTransition
    }}&gt;
      {children}
    &lt;/AppContext.Provider&gt;
  );
};
const useTheme = () =&gt; useContext(ThemeContext);
const useApp = () =&gt; useContext(AppContext);
// --- Collapsible Island Component ---
const CollapsibleIsland = ({ 
  children, 
  title, 
  icon: Icon, 
  position = &apos;left&apos;, 
  defaultCollapsed = false,
  className = &apos;&apos;,
  collapsedHeight = 60 
}) =&gt; {
  const [isCollapsed, setIsCollapsed] = useState(defaultCollapsed);
  const contentRef = useRef(null);
  const toggleCollapsed = () =&gt; {
    setIsCollapsed(!isCollapsed);
  };
  const islandStyles = {
    left: &apos;left-4&apos;,
    right: &apos;right-4&apos;
  };
  return (
    &lt;div 
      className={`
        fixed top-20 ${islandStyles[position]} z-40
        bg-background/95 backdrop-blur-sm border rounded-2xl shadow-2xl
        transition-all duration-500 ease-out
        ${isCollapsed ? &apos;w-16&apos; : &apos;w-80&apos;}
        ${className}
      `}
      style={{
        maxHeight: isCollapsed ? `${collapsedHeight}px` : &apos;calc(100vh - 100px)&apos;
      }}
    &gt;
      {/* Header/Trigger */}
      &lt;div 
        className={`
          flex items-center gap-3 p-4 cursor-pointer
          hover:bg-muted/50 transition-colors duration-200
          ${isCollapsed ? &apos;rounded-2xl justify-center&apos; : &apos;rounded-t-2xl border-b&apos;}
        `}
        onClick={toggleCollapsed}
      &gt;
        &lt;div className={`flex items-center gap-3 ${isCollapsed ? &apos;&apos; : &apos;flex-1&apos;}`}&gt;
          {Icon &amp;&amp; (
            &lt;div className=&quot;w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center&quot;&gt;
              &lt;Icon className=&quot;w-4 h-4 text-primary&quot; /&gt;
            &lt;/div&gt;
          )}
          &lt;span className={`font-medium transition-opacity duration-300 ${isCollapsed ? &apos;opacity-0 w-0 overflow-hidden&apos; : &apos;opacity-100&apos;}`}&gt;
            {title}
          &lt;/span&gt;
        &lt;/div&gt;
        &lt;div className={`transform transition-transform duration-300 ${isCollapsed ? &apos;rotate-0 hidden&apos; : &apos;rotate-180&apos;}`}&gt;
          &lt;Icons.ChevronUp className=&quot;w-4 h-4 text-muted-foreground&quot; /&gt;
        &lt;/div&gt;
      &lt;/div&gt;
      {/* Content */}
      &lt;div 
        ref={contentRef}
        className={`
          overflow-hidden transition-all duration-500 ease-out
          ${isCollapsed ? &apos;max-h-0 opacity-0&apos; : &apos;max-h-[calc(100vh-180px)] opacity-100&apos;}
        `}
      &gt;
        &lt;div className=&quot;overflow-y-auto max-h-full&quot;&gt;
          {children}
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
