// --- AI Assistant as Collapsible Island ---
const AIAssistantIsland = () =&gt; {
  const [message, setMessage] = useState(&apos;&apos;);
  const [chatHistory, setChatHistory] = useState([
    {
      id: 1,
      type: &apos;ai&apos;,
      message: &quot;Hello! I&apos;m your AI writing assistant. How can I help you today?&quot;,
      timestamp: new Date()
    }
  ]);
  const sendMessage = () =&gt; {
    if (!message.trim()) return;
    const userMessage = {
      id: Date.now(),
      type: &apos;user&apos;,
      message: message,
      timestamp: new Date()
    };
    setChatHistory(prev =&gt; [...prev, userMessage]);
    setMessage(&apos;&apos;);
    // Simulate AI response
    setTimeout(() =&gt; {
      const aiMessage = {
        id: Date.now() + 1,
        type: &apos;ai&apos;,
        message: &quot;I understand you&apos;d like help with that. Let me provide some suggestions...&quot;,
        timestamp: new Date()
      };
      setChatHistory(prev =&gt; [...prev, aiMessage]);
    }, 1000);
  };
  return (
    &lt;CollapsibleIsland
      title=&quot;AI Assistant&quot;
      icon={Icons.Bot}
      position=&quot;right&quot;
      defaultCollapsed={false}
    &gt;
      {/* Chat History */}
      &lt;div className=&quot;h-80 overflow-y-auto p-4 space-y-4&quot;&gt;
        {chatHistory.map((chat) =&gt; (
          &lt;div key={chat.id} className={`flex ${chat.type === &apos;user&apos; ? &apos;justify-end&apos; : &apos;justify-start&apos;}`}&gt;
            &lt;div className={`max-w-[85%] p-3 rounded-lg ${
              chat.type === &apos;user&apos; 
                ? &apos;bg-primary text-primary-foreground&apos; 
                : &apos;bg-muted text-foreground&apos;
            }`}&gt;
              &lt;p className=&quot;text-sm&quot;&gt;{chat.message}&lt;/p&gt;
              &lt;div className=&quot;text-xs opacity-70 mt-1&quot;&gt;
                {chat.timestamp.toLocaleTimeString()}
              &lt;/div&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        ))}
      &lt;/div&gt;
      {/* Input */}
      &lt;div className=&quot;border-t p-4&quot;&gt;
        &lt;div className=&quot;flex space-x-2&quot;&gt;
          &lt;input
            type=&quot;text&quot;
            value={message}
            onChange={(e) =&gt; setMessage(e.target.value)}
            onKeyPress={(e) =&gt; e.key === &apos;Enter&apos; &amp;&amp; sendMessage()}
            placeholder=&quot;Ask me anything...&quot;
            className=&quot;flex-1 px-3 py-2 border rounded-lg bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring&quot;
          /&gt;
          &lt;button 
            onClick={sendMessage}
            className=&quot;px-3 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors&quot;
          &gt;
            &lt;Icons.Send className=&quot;w-4 h-4&quot; /&gt;
          &lt;/button&gt;
        &lt;/div&gt;
      &lt;/div&gt;
      {/* Quick Actions */}
      &lt;div className=&quot;border-t p-4&quot;&gt;
        &lt;div className=&quot;grid grid-cols-2 gap-2 text-xs&quot;&gt;
          &lt;button className=&quot;p-2 border rounded-lg hover:bg-muted transition-colors&quot;&gt;
            &lt;Icons.Lightbulb className=&quot;w-3 h-3 mx-auto mb-1&quot; /&gt;
            &lt;div&gt;Plot Ideas&lt;/div&gt;
          &lt;/button&gt;
          &lt;button className=&quot;p-2 border rounded-lg hover:bg-muted transition-colors&quot;&gt;
            &lt;Icons.Users className=&quot;w-3 h-3 mx-auto mb-1&quot; /&gt;
            &lt;div&gt;Characters&lt;/div&gt;
          &lt;/button&gt;
          &lt;button className=&quot;p-2 border rounded-lg hover:bg-muted transition-colors&quot;&gt;
            &lt;Icons.BookOpen className=&quot;w-3 h-3 mx-auto mb-1&quot; /&gt;
            &lt;div&gt;Grammar&lt;/div&gt;
          &lt;/button&gt;
          &lt;button className=&quot;p-2 border rounded-lg hover:bg-muted transition-colors&quot;&gt;
            &lt;Icons.Zap className=&quot;w-3 h-3 mx-auto mb-1&quot; /&gt;
            &lt;div&gt;Enhance&lt;/div&gt;
          &lt;/button&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/CollapsibleIsland&gt;
  );
};
