// --- Enhanced Components ---
// Rich Text Editor Component
const RichTextEditor = ({ value, onChange, placeholder = &quot;Start writing your story...&quot; }) =&gt; {
  const editorRef = useRef(null);
  const quillRef = useRef(null);
  useEffect(() =&gt; {
    if (editorRef.current &amp;&amp; !quillRef.current) {
      quillRef.current = new Quill(editorRef.current, {
        theme: &apos;snow&apos;,
        placeholder: placeholder,
        modules: {
          toolbar: [
            [{ &apos;header&apos;: [1, 2, 3, false] }],
            [&apos;bold&apos;, &apos;italic&apos;, &apos;underline&apos;, &apos;strike&apos;],
            [{ &apos;color&apos;: [] }, { &apos;background&apos;: [] }],
            [{ &apos;list&apos;: &apos;ordered&apos;}, { &apos;list&apos;: &apos;bullet&apos; }],
            [{ &apos;indent&apos;: &apos;-1&apos;}, { &apos;indent&apos;: &apos;+1&apos; }],
            [&apos;blockquote&apos;, &apos;code-block&apos;],
            [&apos;link&apos;, &apos;image&apos;],
            [&apos;clean&apos;]
          ]
        }
      });
      quillRef.current.on(&apos;text-change&apos;, () =&gt; {
        const content = quillRef.current.root.innerHTML;
        onChange?.(content);
      });
    }
    if (quillRef.current &amp;&amp; value !== quillRef.current.root.innerHTML) {
      quillRef.current.root.innerHTML = value || &apos;&apos;;
    }
  }, [value, onChange, placeholder]);
  return (
    &lt;div className=&quot;rich-text-editor&quot;&gt;
      &lt;div ref={editorRef} style={{ minHeight: &apos;400px&apos; }} /&gt;
    &lt;/div&gt;
  );
};
// Character Relationship Web Component
const CharacterRelationshipWeb = ({ characters, onCharacterSelect }) =&gt; {
  const svgRef = useRef(null);
  const [selectedCharacter, setSelectedCharacter] = useState(null);
  const [relationships, setRelationships] = useState([]);
  useEffect(() =&gt; {
    // Generate relationship connections
    const newRelationships = [];
    characters.forEach((char, index) =&gt; {
      char.relationships?.forEach(relName =&gt; {
        const targetChar = characters.find(c =&gt; c.name === relName);
        if (targetChar) {
          newRelationships.push({
            source: index,
            target: characters.indexOf(targetChar),
            type: &apos;connected&apos;
          });
        }
      });
    });
    setRelationships(newRelationships);
  }, [characters]);
  const handleCharacterClick = (character, index) =&gt; {
    setSelectedCharacter(selectedCharacter === index ? null : index);
    onCharacterSelect?.(character);
  };
  // Position characters in a circle
  const centerX = 200;
  const centerY = 200;
  const radius = 120;
  return (
    &lt;div className=&quot;character-web&quot;&gt;
      &lt;svg ref={svgRef} width=&quot;400&quot; height=&quot;400&quot; className=&quot;absolute inset-0&quot;&gt;
        {/* Render relationship lines */}
        {relationships.map((rel, index) =&gt; {
          const sourceAngle = (rel.source / characters.length) * 2 * Math.PI;
          const targetAngle = (rel.target / characters.length) * 2 * Math.PI;
          const x1 = centerX + Math.cos(sourceAngle) * radius;
          const y1 = centerY + Math.sin(sourceAngle) * radius;
          const x2 = centerX + Math.cos(targetAngle) * radius;
          const y2 = centerY + Math.sin(targetAngle) * radius;
          return (
            &lt;line
              key={index}
              x1={x1}
              y1={y1}
              x2={x2}
              y2={y2}
              className={`relationship-line ${selectedCharacter === rel.source || selectedCharacter === rel.target ? &apos;active&apos; : &apos;&apos;}`}
            /&gt;
          );
        })}
      &lt;/svg&gt;
      {/* Render character nodes */}
      {characters.map((character, index) =&gt; {
        const angle = (index / characters.length) * 2 * Math.PI;
        const x = centerX + Math.cos(angle) * radius - 40;
        const y = centerY + Math.sin(angle) * radius - 40;
        return (
          &lt;div
            key={character.id}
            className={`character-node ${selectedCharacter === index ? &apos;selected&apos; : &apos;&apos;}`}
            style={{
              left: `${x}px`,
              top: `${y}px`
            }}
            onClick={() =&gt; handleCharacterClick(character, index)}
            data-tooltip={character.name}
          &gt;
            {character.name.split(&apos; &apos;).map(n =&gt; n[0]).join(&apos;&apos;)}
          &lt;/div&gt;
        );
      })}
    &lt;/div&gt;
  );
};
// Enhanced Story Card Component with Proper Collapsible Functionality
const StoryCard = ({ story, onClick, onEdit }) =&gt; {
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const toggleCollapse = (e) =&gt; {
    e.stopPropagation();
    setIsCollapsed(!isCollapsed);
  };
  return (
    &lt;div 
      className={`bg-card border border-border rounded-lg cursor-pointer overflow-hidden transition-all duration-300 hover:shadow-md hover:-translate-y-0.5 ${
        isCollapsed ? &apos;p-3&apos; : &apos;p-6&apos;
      }`}
      onClick={() =&gt; onClick?.(story)}
      onMouseEnter={() =&gt; setIsHovered(true)}
      onMouseLeave={() =&gt; setIsHovered(false)}
    &gt;
      {/* Header - Always Visible */}
      &lt;div className=&quot;flex items-center justify-between&quot;&gt;
        &lt;div className=&quot;flex items-center space-x-3 flex-1&quot;&gt;
          &lt;div className={`bg-primary rounded-lg flex items-center justify-center text-primary-foreground font-bold transition-all duration-300 ${
            isCollapsed ? &apos;w-8 h-8 text-sm&apos; : &apos;w-12 h-12&apos;
          }`}&gt;
            {story.title[0]}
          &lt;/div&gt;
          &lt;div className=&quot;flex-1 min-w-0&quot;&gt;
            &lt;h3 className={`font-bold truncate transition-all duration-300 ${
              isCollapsed ? &apos;text-base&apos; : &apos;text-lg&apos;
            }`}&gt;
              {story.title}
            &lt;/h3&gt;
            &lt;p className=&quot;text-muted-foreground text-sm truncate&quot;&gt;{story.genre}&lt;/p&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div className=&quot;flex items-center&quot;&gt;
          {/* Collapse/Expand Toggle */}
          &lt;button
            className=&quot;p-2 rounded hover:bg-muted cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&quot;
            onClick={toggleCollapse}
            aria-label={isCollapsed ? &quot;Expand card&quot; : &quot;Collapse card&quot;}
          &gt;
            &lt;i 
              data-feather={isCollapsed ? &quot;chevron-down&quot; : &quot;chevron-up&quot;} 
              className={`w-4 h-4 transition-transform duration-200 ${isCollapsed ? &apos;rotate-0&apos; : &apos;rotate-180&apos;}`}
            &gt;&lt;/i&gt;
          &lt;/button&gt;
          {/* Edit Button - only show when not collapsed and hovered */}
          {!isCollapsed &amp;&amp; (
            &lt;div className={`transition-opacity duration-200 ${isHovered ? &apos;opacity-100&apos; : &apos;opacity-0&apos;}`}&gt;
              &lt;button
                className=&quot;p-2 rounded hover:bg-muted cursor-pointer select-none transition-all duration-200 hover:scale-105 active:scale-95&quot;
                onClick={(e) =&gt; { e.stopPropagation(); onEdit?.(story); }}
                aria-label=&quot;Edit story&quot;
              &gt;
                &lt;i data-feather=&quot;edit-2&quot; className=&quot;w-4 h-4&quot;&gt;&lt;/i&gt;
              &lt;/button&gt;
            &lt;/div&gt;
          )}
        &lt;/div&gt;
      &lt;/div&gt;
      {/* Collapsible Content */}
      &lt;div 
        className={`overflow-hidden transition-all duration-300 ease-out ${
          isCollapsed 
            ? &apos;max-h-0 opacity-0 mt-0&apos; 
            : &apos;max-h-96 opacity-100 mt-4&apos;
        }`}
        style={{
          transform: isCollapsed ? &apos;scaleY(0)&apos; : &apos;scaleY(1)&apos;,
          transformOrigin: &apos;top&apos;
        }}
      &gt;
        &lt;div className=&quot;space-y-3&quot;&gt;
          &lt;div className=&quot;flex justify-between text-sm&quot;&gt;
            &lt;span className=&quot;text-muted-foreground&quot;&gt;Progress&lt;/span&gt;
            &lt;span className=&quot;font-medium&quot;&gt;{story.progress}%&lt;/span&gt;
          &lt;/div&gt;
          &lt;div className=&quot;w-full bg-muted rounded-full h-2&quot;&gt;
            &lt;div 
              className=&quot;bg-primary h-2 rounded-full transition-all duration-500&quot;
              style={{ width: `${story.progress}%` }}
            /&gt;
          &lt;/div&gt;
          &lt;div className=&quot;flex items-center justify-between text-sm text-muted-foreground&quot;&gt;
            &lt;span&gt;{story.chapters} chapters&lt;/span&gt;
            &lt;span&gt;{story.words.toLocaleString()} words&lt;/span&gt;
          &lt;/div&gt;
          &lt;div className=&quot;text-xs text-muted-foreground flex items-center&quot;&gt;
            &lt;Icons.Clock /&gt;
            &lt;span className=&quot;ml-1&quot;&gt;Last edited {story.lastEdited}&lt;/span&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
