                      &lt;Icons.Edit /&gt;
                      &lt;span className=&quot;ml-1&quot;&gt;Edit&lt;/span&gt;
                    &lt;/Button&gt;
                    &lt;Button variant=&quot;outline&quot; size=&quot;sm&quot; className=&quot;flex-1&quot;&gt;
                      &lt;Icons.FileText /&gt;
                      &lt;span className=&quot;ml-1&quot;&gt;Profile&lt;/span&gt;
                    &lt;/Button&gt;
                  &lt;/div&gt;
                &lt;/div&gt;
              &lt;/div&gt;
            )}
          &lt;/div&gt;
        ))}
      &lt;/div&gt;
      {/* Add Character Modal */}
      {showAddCharacter &amp;&amp; (
        &lt;div className=&quot;fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-fade-in&quot;&gt;
          &lt;div className=&quot;bg-card p-6 rounded-lg border max-w-md w-full mx-4 animate-scale-in&quot;&gt;
            &lt;div className=&quot;flex items-center justify-between mb-4&quot;&gt;
              &lt;h4 className=&quot;font-medium&quot;&gt;Add New Character&lt;/h4&gt;
              &lt;Button 
                variant=&quot;ghost&quot; 
                size=&quot;sm&quot;
                onClick={() =&gt; setShowAddCharacter(false)}
              &gt;
                &lt;Icons.X /&gt;
              &lt;/Button&gt;
            &lt;/div&gt;
            &lt;div className=&quot;space-y-4&quot;&gt;
              &lt;input 
                type=&quot;text&quot; 
                placeholder=&quot;Character name&quot;
                className=&quot;w-full p-2 border rounded&quot;
              /&gt;
              &lt;textarea 
                placeholder=&quot;Character description&quot;
                className=&quot;w-full p-2 border rounded h-20 resize-none&quot;
              /&gt;
              &lt;select className=&quot;w-full p-2 border rounded&quot;&gt;
                &lt;option&gt;Select role...&lt;/option&gt;
                &lt;option&gt;Protagonist&lt;/option&gt;
                &lt;option&gt;Deuteragonist&lt;/option&gt;
                &lt;option&gt;Antagonist&lt;/option&gt;
                &lt;option&gt;Supporting&lt;/option&gt;
              &lt;/select&gt;
              &lt;div className=&quot;flex space-x-2&quot;&gt;
                &lt;Button 
                  className=&quot;flex-1&quot;
                  onClick={() =&gt; setShowAddCharacter(false)}
                &gt;
                  Add Character
                &lt;/Button&gt;
                &lt;Button 
                  variant=&quot;outline&quot; 
                  className=&quot;flex-1&quot;
                  onClick={() =&gt; setShowAddCharacter(false)}
                &gt;
                  Cancel
                &lt;/Button&gt;
              &lt;/div&gt;
            &lt;/div&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      )}
    &lt;/div&gt;
  );
};
// Enhanced AI Assistant Component with Categorized Suggestions
const AIAssistant = () =&gt; {
  const { aiAssistantOpen, setAiAssistantOpen } = useApp();
  const [selectedSuggestion, setSelectedSuggestion] = useState(null);
  const [activeCategory, setActiveCategory] = useState(&apos;all&apos;);
  const [isTyping, setIsTyping] = useState(false);
  const categories = [
    { id: &apos;all&apos;, label: &apos;All&apos;, icon: &apos;Grid&apos; },
    { id: &apos;Character Development&apos;, label: &apos;Characters&apos;, icon: &apos;Users&apos; },
    { id: &apos;Plot Development&apos;, label: &apos;Plot&apos;, icon: &apos;BookOpen&apos; },
    { id: &apos;World Building&apos;, label: &apos;World&apos;, icon: &apos;Globe&apos; },
    { id: &apos;Dialogue&apos;, label: &apos;Dialogue&apos;, icon: &apos;MessageCircle&apos; }
  ];
  const filteredSuggestions = activeCategory === &apos;all&apos; 
    ? mockAISuggestions 
    : mockAISuggestions.filter(s =&gt; s.category === activeCategory);
  const handleSuggestionClick = (suggestion) =&gt; {
