          data-tooltip={`Switch to ${theme === &apos;light&apos; ? &apos;dark&apos; : &apos;light&apos;} mode`}
        &gt;
          {theme === &apos;light&apos; ? &lt;Icons.Moon /&gt; : &lt;Icons.Sun /&gt;}
