      &lt;div className=&quot;text-center max-w-md mx-auto p-8&quot;&gt;
        {/* Icon */}
        &lt;div className=&quot;mb-6&quot;&gt;
          &lt;div className=&quot;w-24 h-24 mx-auto bg-white/10 rounded-full flex items-center justify-center&quot;&gt;
