          &lt;/p&gt;
        )}
      &lt;/div&gt;
    &lt;/div&gt;
  );
};
// Enhanced Navigation Component
const NavigationTabs = () =&gt; {
  const { currentRoute, navigate, activeRoutes, comingSoonRoutes } = useRouter();
  const Icons = window.Icons; // Use global Icons from app.js
  const cn = window.cn; // Use global cn utility from app.js
  return (
    &lt;nav className=&quot;hidden md:flex space-x-2&quot;&gt;
      {/* Active Routes */}
      {activeRoutes.map((route) =&gt; (
        &lt;button
          key={route.path}
          onClick={() =&gt; navigate(route)}
          className={cn(
            &apos;px-3 py-2 rounded-md text-sm font-medium transition-all duration-150 ease-in-out cursor-pointer border-0 bg-transparent text-foreground no-underline hover:bg-accent hover:text-accent-foreground&apos;,
            currentRoute.path === route.path ? &apos;bg-primary text-primary-foreground&apos; : &apos;&apos;
          )}
        &gt;
          {route.icon === &apos;edit-3&apos; &amp;&amp; &lt;Icons.Edit /&gt;}
          {route.icon === &apos;film&apos; &amp;&amp; &lt;Icons.Film /&gt;}
          {route.icon === &apos;play&apos; &amp;&amp; &lt;Icons.Play /&gt;}
          &lt;span className=&quot;ml-2&quot;&gt;{route.name}&lt;/span&gt;
          {route.shortcut &amp;&amp; (
            &lt;kbd className=&quot;ml-2 text-xs opacity-60&quot;&gt;{route.shortcut}&lt;/kbd&gt;
          )}
        &lt;/button&gt;
      ))}
      {/* Coming Soon Indicator */}
      {comingSoonRoutes.length &gt; 0 &amp;&amp; (
        &lt;div className=&quot;flex items-center space-x-1 ml-4&quot;&gt;
          &lt;div className=&quot;w-1 h-6 bg-border&quot;&gt;&lt;/div&gt;
          &lt;button
            className=&quot;px-2 py-1 text-xs text-muted-foreground hover:text-foreground transition-colors&quot;
            title={`${comingSoonRoutes.length} more modules coming soon`}
          &gt;
            +{comingSoonRoutes.length} more
          &lt;/button&gt;
        &lt;/div&gt;
      )}
    &lt;/nav&gt;
  );
};
// Make routing system globally available
window.RouterProvider = RouterProvider;
window.useRouter = useRouter;
window.routes = routes;
window.NavigationTabs = NavigationTabs;
window.ComingSoonPlaceholder = ComingSoonPlaceholder;
window.getRouteByPath = getRouteByPath;
window.getRouteByName = getRouteByName;
window.getActiveRoutes = getActiveRoutes;
window.getComingSoonRoutes = getComingSoonRoutes;
// Debug: Log to console that routing system is loaded
console.log(&apos;Routing system loaded successfully:&apos;, {
  RouterProvider: !!window.RouterProvider,
  useRouter: !!window.useRouter,
  NavigationTabs: !!window.NavigationTabs,
  ComingSoonPlaceholder: !!window.ComingSoonPlaceholder
